/* ============================================================
   Verb Tenses Data — Part 1 (Tenses 1–6 of 12)
   For PTE Academic Study Planner
   Covers: Simple Present, Present Continuous, Present Perfect,
           Present Perfect Continuous, Simple Past, Past Continuous
   Total: 510 exercises (85 per tense)
   ============================================================ */

var VERB_TENSES_1 = [
  {
    id: "simple-present",
    name: "Simple Present",
    formula: "Subject + base verb (+s/es for 3rd person)",
    negFormula: "Subject + do/does + not + base verb",
    qFormula: "Do/Does + subject + base verb?",
    usage: ["Habits and routines","General facts/truths","Permanent states","Scheduled events","Zero conditionals"],
    signalWords: ["always","usually","often","sometimes","never","every day","on Mondays","generally","frequently","rarely"],
    examples: {pos:"She works in a hospital.",neg:"She does not work in a hospital.",q:"Does she work in a hospital?"},
    exercises: [
      {id:"sp001",type:"fill",q:"The government ___ (allocate) funding for public education every year.",a:"allocates",exp:"Third person singular subject 'the government' requires the -s ending on the base verb."},
      {id:"sp002",type:"fill",q:"Researchers ___ (analyse) data to identify trends in climate change.",a:"analyse",exp:"Plural subject 'researchers' takes the base form. Note Australian spelling: analyse (not analyze)."},
      {id:"sp003",type:"fill",q:"The university ___ (offer) scholarships to international students.",a:"offers",exp:"Third person singular 'the university' requires -s. This describes a permanent or habitual action."},
      {id:"sp004",type:"fill",q:"Air pollution ___ (cause) serious respiratory diseases in urban areas.",a:"causes",exp:"Singular subject 'air pollution' takes -s. This is a general fact."},
      {id:"sp005",type:"fill",q:"Students ___ (attend) lectures every weekday during the semester.",a:"attend",exp:"Plural subject 'students' takes the base form. 'Every weekday' signals a habitual action."},
      {id:"sp006",type:"fill",q:"The hospital ___ (provide) free healthcare to low-income families.",a:"provides",exp:"Third person singular requires -s. This describes a permanent state or ongoing service."},
      {id:"sp007",type:"fill",q:"Technology ___ (transform) the way people communicate globally.",a:"transforms",exp:"Singular uncountable subject 'technology' takes -s. This describes a general truth."},
      {id:"sp008",type:"fill",q:"The committee ___ (meet) on the first Monday of every month.",a:"meets",exp:"'The committee' is treated as singular in formal English, requiring -s. 'Every month' signals routine."},
      {id:"sp009",type:"fill",q:"Renewable energy ___ (reduce) dependence on fossil fuels.",a:"reduces",exp:"Singular subject requires -s. This states a general fact about renewable energy."},
      {id:"sp010",type:"fill",q:"Many economists ___ (believe) that free trade ___ (benefit) developing nations.",a:"believe ... benefits",exp:"'Many economists' is plural (base form). 'Free trade' is singular (requires -s)."},
      {id:"sp011",type:"fill",q:"The professor ___ (not/accept) late submissions under any circumstances.",a:"does not accept",exp:"Negative simple present for third person singular uses 'does not' + base verb."},
      {id:"sp012",type:"fill",q:"This policy ___ (not/address) the root causes of poverty.",a:"does not address",exp:"Negative with third person singular: does not + base verb. Common error: 'does not addresses'."},
      {id:"sp013",type:"fill",q:"Children who ___ (read) regularly ___ (develop) stronger vocabulary skills.",a:"read ... develop",exp:"Both subjects are plural, so both verbs take the base form. This is a general truth."},
      {id:"sp014",type:"fill",q:"The exam ___ (start) at 9 a.m. tomorrow.",a:"starts",exp:"Simple present is used for scheduled future events. Third person singular takes -s."},
      {id:"sp015",type:"fill",q:"If the temperature ___ (rise), sea levels ___ (increase).",a:"rises ... increase",exp:"Zero conditional uses simple present in both clauses. 'Temperature' is singular; 'levels' is plural."},
      {id:"sp016",type:"fill",q:"The report ___ (highlight) key challenges in the healthcare system.",a:"highlights",exp:"Singular subject 'the report' requires -s."},
      {id:"sp017",type:"fill",q:"Public transport ___ (not/reach) many rural communities effectively.",a:"does not reach",exp:"Negative simple present: does not + base verb for singular subjects."},
      {id:"sp018",type:"fill",q:"Vaccination programmes ___ (protect) communities from infectious diseases.",a:"protect",exp:"Plural subject 'programmes' takes the base form. Note Australian spelling: programmes."},
      {id:"sp019",type:"fill",q:"The library ___ (close) at 6 p.m. on weekdays.",a:"closes",exp:"Scheduled event uses simple present. Singular subject takes -s."},
      {id:"sp020",type:"fill",q:"Social media ___ (influence) public opinion on political issues.",a:"influences",exp:"'Social media' is typically treated as singular, requiring -s."},
      {id:"sp021",type:"fill",q:"Each student ___ (receive) personalised feedback on their assignments.",a:"receives",exp:"'Each student' is always singular, requiring -s. Note Australian spelling: personalised."},
      {id:"sp022",type:"fill",q:"The bus ___ (depart) from the station at 7:30 every morning.",a:"departs",exp:"Scheduled/timetabled events use simple present. Singular subject takes -s."},
      {id:"sp023",type:"fill",q:"Water ___ (boil) at 100 degrees Celsius at standard atmospheric pressure.",a:"boils",exp:"Scientific fact uses simple present. Singular uncountable noun takes -s."},
      {id:"sp024",type:"fill",q:"The organisation ___ (recognise) the need for environmental reform.",a:"recognises",exp:"Singular subject takes -s. Note Australian spelling: organisation, recognise."},
      {id:"sp025",type:"fill",q:"Effective teachers ___ (adapt) their methods to suit different learning styles.",a:"adapt",exp:"Plural subject 'teachers' takes the base form. This describes a general truth about teaching."},
      {id:"sp026",type:"mc",q:"Which sentence correctly uses the simple present tense?",options:["The government invest heavily in education.","The government invests heavily in education.","The government investing heavily in education.","The government is invest heavily in education."],a:1,exp:"'The government' is third person singular, so the verb needs -s: invests."},
      {id:"sp027",type:"mc",q:"Choose the correct negative form: 'She ___ with the new policy.'",options:["don't agree","doesn't agrees","does not agree","not agrees"],a:2,exp:"Third person singular negative: does not + base verb. 'Does not agree' is correct."},
      {id:"sp028",type:"mc",q:"Which sentence expresses a general truth?",options:["The earth was revolving around the sun.","The earth revolves around the sun.","The earth is revolving around the sun.","The earth has revolved around the sun."],a:1,exp:"General/scientific truths use simple present: 'revolves'."},
      {id:"sp029",type:"mc",q:"Select the correct question form: '___ the university offer online courses?'",options:["Do","Does","Is","Are"],a:1,exp:"'The university' is third person singular, so the auxiliary is 'Does'."},
      {id:"sp030",type:"mc",q:"Which signal word typically accompanies the simple present?",options:["right now","yesterday","every semester","since 2020"],a:2,exp:"'Every semester' indicates a regular habit or routine, which requires simple present."},
      {id:"sp031",type:"mc",q:"Choose the correct form: 'Researchers frequently ___ new methods.'",options:["develops","develop","is developing","has developed"],a:1,exp:"Plural subject 'researchers' + frequency adverb 'frequently' = simple present base form."},
      {id:"sp032",type:"mc",q:"Which sentence is grammatically correct?",options:["The data shows a significant trend.","The data show a significant trend.","Both A and B are acceptable.","Neither A nor B is correct."],a:2,exp:"'Data' can be treated as singular or plural in modern usage. Both forms are widely accepted."},
      {id:"sp033",type:"mc",q:"Select the correct zero conditional: 'If you ___ water to 100°C, it ___.'",options:["heat / boils","heats / boil","heated / boils","heat / boiled"],a:0,exp:"Zero conditional: If + simple present, simple present. 'You heat' (base) and 'it boils' (3rd person -s)."},
      {id:"sp034",type:"mc",q:"Which is correct for a scheduled event? 'The conference ___ next Friday.'",options:["is starting","starts","will start","started"],a:1,exp:"Scheduled/timetabled future events use simple present: 'starts'."},
      {id:"sp035",type:"mc",q:"Choose the correct form: 'Neither the teacher nor the students ___ the results.'",options:["knows","know","is knowing","has known"],a:1,exp:"With 'neither...nor', the verb agrees with the nearer subject: 'students' (plural) = 'know'."},
      {id:"sp036",type:"mc",q:"Which sentence has correct subject-verb agreement?",options:["The number of applicants are increasing.","The number of applicants is increasing.","A number of applicants is applying.","Every students need support."],a:1,exp:"'The number of' is singular and takes 'is'. Compare: 'A number of' is plural and takes 'are'."},
      {id:"sp037",type:"mc",q:"Select the correct option: 'Economics ___ a challenging subject for many students.'",options:["are","is","were","have been"],a:1,exp:"'Economics' is an uncountable noun (academic discipline) treated as singular: 'is'."},
      {id:"sp038",type:"mc",q:"Which adverb placement is correct?",options:["She always arrives on time.","She arrives always on time.","Always she arrives on time.","She on time always arrives."],a:0,exp:"Frequency adverbs go before the main verb: 'always arrives'."},
      {id:"sp039",type:"mc",q:"Choose the correct form: 'The news ___ that the economy ___ signs of recovery.'",options:["report / show","reports / shows","report / shows","reports / show"],a:1,exp:"'The news' is uncountable singular (reports); 'the economy' is singular (shows)."},
      {id:"sp040",type:"mc",q:"Which sentence uses the simple present for a permanent state?",options:["She is living in Sydney.","She lives in Sydney.","She has lived in Sydney.","She lived in Sydney."],a:1,exp:"Simple present for permanent states: 'lives'. Present continuous would imply a temporary situation."},
      {id:"sp041",type:"mc",q:"Select the correct question: '___ your organisation recognise international qualifications?'",options:["Do","Does","Is","Has"],a:1,exp:"'Your organisation' is third person singular, requiring 'Does'. Note Australian spelling: organisation, recognise."},
      {id:"sp042",type:"mc",q:"Which sentence correctly uses 'do not' in simple present?",options:["The findings do not supports the hypothesis.","The findings does not support the hypothesis.","The findings do not support the hypothesis.","The findings not support the hypothesis."],a:2,exp:"Plural subject 'findings' uses 'do not' + base verb 'support'."},
      {id:"sp043",type:"mc",q:"Choose the correct form: 'Each of the participants ___ a consent form before the study.'",options:["sign","signs","are signing","have signed"],a:1,exp:"'Each of' is always singular, so the verb takes -s: 'signs'. This describes a routine procedure."},
      {id:"sp044",type:"mc",q:"Which is correct? 'The curriculum ___ courses in both arts and sciences.'",options:["include","includes","is including","are including"],a:1,exp:"'The curriculum' is singular, requiring -s: 'includes'. This describes a permanent feature."},
      {id:"sp045",type:"mc",q:"Select the sentence with correct subject-verb agreement:",options:["There is many factors to consider.","There are many factors to consider.","There has many factors to consider.","There have many factors to consider."],a:1,exp:"In 'there + be' constructions, the verb agrees with the real subject: 'factors' (plural) = 'are'."},
      {id:"sp046",type:"mc",q:"Which sentence correctly expresses a habit?",options:["He is reading academic journals every week.","He reads academic journals every week.","He has read academic journals every week.","He read academic journals every week."],a:1,exp:"Habits with frequency expressions ('every week') use simple present: 'reads'."},
      {id:"sp047",type:"mc",q:"Choose the correct option: 'The government, along with local councils, ___ responsible for urban planning.'",options:["are","is","were","have been"],a:1,exp:"'Along with' does not change the subject. The subject is 'the government' (singular): 'is'."},
      {id:"sp048",type:"mc",q:"Which pair both use simple present correctly?",options:["She teach English. / They learns quickly.","She teaches English. / They learn quickly.","She is teaching English. / They are learning quickly.","She taught English. / They learnt quickly."],a:1,exp:"She (singular) = teaches; They (plural) = learn. Both simple present with correct agreement."},
      {id:"sp049",type:"mc",q:"Select the correct sentence about a timetabled event:",options:["The semester is beginning on 1 March.","The semester begins on 1 March.","The semester will begin on 1 March.","The semester begun on 1 March."],a:1,exp:"Timetabled events use simple present: 'begins'. This is a fixed schedule."},
      {id:"sp050",type:"mc",q:"Which sentence contains a subject-verb agreement error?",options:["The results indicate a positive trend.","The analysis suggests further research is needed.","The criteria for selection includes work experience.","The phenomenon occurs in tropical regions."],a:2,exp:"'Criteria' is the plural of 'criterion' and requires a plural verb: 'include', not 'includes'."},
      {id:"sp051",type:"error",q:"The government don't invest enough in renewable energy sources.",a:"The government doesn't invest enough in renewable energy sources.",exp:"'The government' is third person singular, so it requires 'doesn't' (does not), not 'don't' (do not)."},
      {id:"sp052",type:"error",q:"Technology change the way we communicate with each other.",a:"Technology changes the way we communicate with each other.",exp:"Third person singular 'technology' requires -s: 'changes'. Forgetting the -s is a common error for Chinese speakers."},
      {id:"sp053",type:"error",q:"The professor always give detailed feedback on student essays.",a:"The professor always gives detailed feedback on student essays.",exp:"Third person singular 'the professor' requires -s: 'gives'."},
      {id:"sp054",type:"error",q:"Every student need access to reliable internet for online learning.",a:"Every student needs access to reliable internet for online learning.",exp:"'Every student' is singular and requires -s: 'needs'."},
      {id:"sp055",type:"error",q:"The data indicates that unemployment are rising in regional areas.",a:"The data indicates that unemployment is rising in regional areas.",exp:"'Unemployment' is an uncountable singular noun, requiring 'is', not 'are'."},
      {id:"sp056",type:"error",q:"She don't believe that standardised testing accurately measure student ability.",a:"She doesn't believe that standardised testing accurately measures student ability.",exp:"Two errors: 'She' requires 'doesn't'; 'testing' (singular) requires 'measures'."},
      {id:"sp057",type:"error",q:"The cost of living in major cities continue to rise each year.",a:"The cost of living in major cities continues to rise each year.",exp:"The subject is 'the cost' (singular), not 'cities'. Therefore: 'continues'."},
      {id:"sp058",type:"error",q:"Education play a vital role in reducing social inequality.",a:"Education plays a vital role in reducing social inequality.",exp:"Singular uncountable 'education' requires -s: 'plays'."},
      {id:"sp059",type:"error",q:"The committee meet every Tuesday but they doesn't always reach a decision.",a:"The committee meets every Tuesday but they don't always reach a decision.",exp:"'Committee' (singular) = 'meets'. 'They' (plural) = 'don't'. Two agreement errors corrected."},
      {id:"sp060",type:"error",q:"Neither the students nor the teacher are satisfied with the new timetable.",a:"Neither the students nor the teacher is satisfied with the new timetable.",exp:"With 'neither...nor', the verb agrees with the nearer subject: 'the teacher' (singular) = 'is'."},
      {id:"sp061",type:"error",q:"Many people believes that public health is more important than economic growth.",a:"Many people believe that public health is more important than economic growth.",exp:"'Many people' is plural, requiring the base form: 'believe', not 'believes'."},
      {id:"sp062",type:"error",q:"The news show that the economy recover slowly from the recession.",a:"The news shows that the economy recovers slowly from the recession.",exp:"'The news' is uncountable singular: 'shows'. 'The economy' is singular: 'recovers'."},
      {id:"sp063",type:"error",q:"Each of the students have a responsibility to participate in group discussions.",a:"Each of the students has a responsibility to participate in group discussions.",exp:"'Each of' is always singular, requiring 'has', not 'have'."},
      {id:"sp064",type:"error",q:"The number of international students are increasing every year.",a:"The number of international students is increasing every year.",exp:"'The number of' is singular and takes 'is'. Do not confuse with 'a number of' (plural)."},
      {id:"sp065",type:"error",q:"Physics are a compulsory subject in many secondary school programmes.",a:"Physics is a compulsory subject in many secondary school programmes.",exp:"Academic subjects ending in -s (physics, mathematics, economics) are singular: 'is'."},
      {id:"sp066",type:"error",q:"The criteria for admission includes a minimum IELTS score of 7.0.",a:"The criteria for admission include a minimum IELTS score of 7.0.",exp:"'Criteria' is the plural of 'criterion' and requires the plural verb 'include'."},
      {id:"sp067",type:"error",q:"The staff in the department works collaboratively, but each member have different specialisations.",a:"The staff in the department work collaboratively, but each member has different specialisations.",exp:"'Staff' (collective, plural sense) = 'work'. 'Each member' (singular) = 'has'."},
      {id:"sp068",type:"error",q:"Pollution from factories contribute to global warming and damages ecosystems.",a:"Pollution from factories contributes to global warming and damages ecosystems.",exp:"Subject is 'pollution' (singular), not 'factories'. Requires 'contributes'. 'Damages' is already correct."},
      {id:"sp069",type:"error",q:"A significant percentage of the population do not has access to clean water.",a:"A significant percentage of the population does not have access to clean water.",exp:"Negative form: does not + base verb 'have'. 'Does not has' is always wrong."},
      {id:"sp070",type:"error",q:"The research suggest that exercise reduce the risk of heart disease.",a:"The research suggests that exercise reduces the risk of heart disease.",exp:"Both 'research' and 'exercise' are singular/uncountable, requiring -s: 'suggests', 'reduces'."},
      {id:"sp071",type:"transform",q:"The university provides free counselling services. [Make negative]",a:"The university does not provide free counselling services.",exp:"Negative simple present (3rd person singular): subject + does not + base verb."},
      {id:"sp072",type:"transform",q:"Students submit assignments online. [Make into a question]",a:"Do students submit assignments online?",exp:"Question form with plural subject: Do + subject + base verb?"},
      {id:"sp073",type:"transform",q:"The hospital does not accept walk-in patients. [Make affirmative]",a:"The hospital accepts walk-in patients.",exp:"Remove 'does not' and add -s to the base verb for third person singular."},
      {id:"sp074",type:"transform",q:"Climate change affects biodiversity around the world. [Make into a yes/no question]",a:"Does climate change affect biodiversity around the world?",exp:"Question form: Does + singular subject + base verb (no -s on main verb)?"},
      {id:"sp075",type:"transform",q:"The teacher explained the topic yesterday. [Change to simple present — habitual]",a:"The teacher explains the topic every day.",exp:"Change past tense to present tense with a habitual time marker. 'Explains' for 3rd person singular."},
      {id:"sp076",type:"transform",q:"Do they organise community events? [Change to a statement]",a:"They organise community events.",exp:"Remove the auxiliary 'Do' and use the base form with plural subject."},
      {id:"sp077",type:"transform",q:"The government is investing in infrastructure. [Rewrite as a general fact in simple present]",a:"The government invests in infrastructure.",exp:"Change from present continuous (temporary) to simple present (general fact/permanent policy)."},
      {id:"sp078",type:"transform",q:"Nurses work long shifts. The hospital provides additional support. [Combine with 'so']",a:"Nurses work long shifts, so the hospital provides additional support.",exp:"Join two simple present sentences with a comma and the coordinating conjunction 'so'."},
      {id:"sp079",type:"transform",q:"Researchers have discovered a new treatment. [Rewrite in simple present]",a:"Researchers discover a new treatment.",exp:"Change from present perfect to simple present. Plural subject takes base form."},
      {id:"sp080",type:"transform",q:"She doesn't attend the weekly meetings. [Make affirmative and add a frequency adverb]",a:"She always attends the weekly meetings.",exp:"Remove 'doesn't', add -s for 3rd person singular, and insert a frequency adverb."},
      {id:"sp081",type:"transform",q:"Environmental regulations protect natural habitats. [Rewrite as a negative question]",a:"Don't environmental regulations protect natural habitats?",exp:"Negative question: Don't + plural subject + base verb? Used for rhetorical effect."},
      {id:"sp082",type:"transform",q:"Does the policy favour large corporations? [Change to a negative statement]",a:"The policy does not favour large corporations.",exp:"Negative statement: subject + does not + base verb. Note Australian spelling: favour."},
      {id:"sp083",type:"transform",q:"Many students struggle with academic writing. [Add 'if' to create a zero conditional]",a:"If many students struggle with academic writing, they need additional support.",exp:"Zero conditional: If + simple present, simple present. Both clauses use present tense for general truths."},
      {id:"sp084",type:"transform",q:"The professor does not allow mobile phones in class. [Make into a question]",a:"Does the professor allow mobile phones in class?",exp:"Remove 'not' and invert: Does + subject + base verb?"},
      {id:"sp085",type:"transform",q:"They don't recognise the importance of mental health in the workplace. [Make affirmative]",a:"They recognise the importance of mental health in the workplace.",exp:"Remove 'don't' and keep the base form for plural subject. Australian spelling: recognise."}
    ]
  },
  {
    id: "present-continuous",
    name: "Present Continuous",
    formula: "Subject + am/is/are + verb-ing",
    negFormula: "Subject + am/is/are + not + verb-ing",
    qFormula: "Am/Is/Are + subject + verb-ing?",
    usage: ["Actions happening now","Temporary situations","Future arrangements","Changing/developing situations","Annoying habits (with always)"],
    signalWords: ["now","right now","at the moment","currently","today","this week","still","at present"],
    examples: {pos:"She is studying for her PTE exam.",neg:"She is not studying now.",q:"Is she studying for her PTE exam?"},
    exercises: [
      {id:"pc001",type:"fill",q:"The researcher ___ (conduct) a survey on public health awareness right now.",a:"is conducting",exp:"Action happening now: am/is/are + verb-ing. Singular subject 'researcher' takes 'is'."},
      {id:"pc002",type:"fill",q:"Students ___ (prepare) for their final examinations this week.",a:"are preparing",exp:"Plural subject 'students' takes 'are'. 'This week' signals a current temporary activity."},
      {id:"pc003",type:"fill",q:"The government ___ (implement) new environmental regulations at present.",a:"is implementing",exp:"Singular subject with 'at present' signals an ongoing current action: is + verb-ing."},
      {id:"pc004",type:"fill",q:"I ___ (write) my thesis on the impact of technology on education.",a:"am writing",exp:"First person singular uses 'am' + verb-ing. This describes a current ongoing project."},
      {id:"pc005",type:"fill",q:"The climate ___ (change) more rapidly than scientists predicted.",a:"is changing",exp:"Changing/developing situations use present continuous. Singular subject takes 'is'."},
      {id:"pc006",type:"fill",q:"More universities ___ (offer) online programmes to attract international students.",a:"are offering",exp:"Developing trend uses present continuous. Plural subject takes 'are'. Australian spelling: programmes."},
      {id:"pc007",type:"fill",q:"She ___ (not/attend) the conference this year due to budget constraints.",a:"is not attending",exp:"Negative present continuous: is + not + verb-ing. Future arrangement that has been decided."},
      {id:"pc008",type:"fill",q:"The hospital ___ (expand) its emergency department to meet growing demand.",a:"is expanding",exp:"Temporary project in progress uses present continuous: is + verb-ing."},
      {id:"pc009",type:"fill",q:"Pollution levels ___ (rise) steadily in developing countries.",a:"are rising",exp:"Changing situation/trend uses present continuous. Plural 'levels' takes 'are'."},
      {id:"pc010",type:"fill",q:"The professor ___ (review) the latest research findings at the moment.",a:"is reviewing",exp:"'At the moment' signals an action happening now. Singular subject takes 'is'."},
      {id:"pc011",type:"fill",q:"We ___ (organise) a fundraising event for the scholarship programme next Saturday.",a:"are organising",exp:"Future arrangement uses present continuous. Plural 'we' takes 'are'. Australian spelling: organise."},
      {id:"pc012",type:"fill",q:"The cost of healthcare ___ (increase) dramatically this decade.",a:"is increasing",exp:"Developing trend uses present continuous. 'Cost' (singular) takes 'is'."},
      {id:"pc013",type:"fill",q:"He ___ (always/complain) about the workload, even when it is reasonable.",a:"is always complaining",exp:"'Always' + present continuous expresses an annoying or irritating repeated habit."},
      {id:"pc014",type:"fill",q:"The team ___ (analyse) the survey results this afternoon.",a:"is analysing",exp:"Temporary activity happening around now. 'Team' (singular) takes 'is'. Australian spelling: analysing."},
      {id:"pc015",type:"fill",q:"Governments around the world ___ (invest) in renewable energy infrastructure.",a:"are investing",exp:"Current developing trend. Plural 'governments' takes 'are'."},
      {id:"pc016",type:"fill",q:"The patient ___ (recover) well after the surgery.",a:"is recovering",exp:"Temporary situation in progress. Singular subject takes 'is'."},
      {id:"pc017",type:"fill",q:"Researchers ___ (develop) a new vaccine for the emerging virus.",a:"are developing",exp:"Action in progress around now. Plural subject takes 'are'."},
      {id:"pc018",type:"fill",q:"The school ___ (not/accept) new enrolments at the moment.",a:"is not accepting",exp:"Negative present continuous: is + not + verb-ing. 'At the moment' signals current temporary state."},
      {id:"pc019",type:"fill",q:"Technology companies ___ (hire) more data scientists this year.",a:"are hiring",exp:"Current trend with 'this year'. Plural subject takes 'are'."},
      {id:"pc020",type:"fill",q:"The city council ___ (plan) a new public transport network.",a:"is planning",exp:"Current project in progress. Singular 'council' takes 'is'."},
      {id:"pc021",type:"fill",q:"She ___ (currently/work) on a project about sustainable urban design.",a:"is currently working",exp:"'Currently' signals present continuous. Adverb goes between 'is' and 'verb-ing'."},
      {id:"pc022",type:"fill",q:"The population of major cities ___ (grow) at an unprecedented rate.",a:"is growing",exp:"Changing/developing situation. Subject 'population' (singular) takes 'is'."},
      {id:"pc023",type:"fill",q:"They ___ (not/use) traditional teaching methods anymore.",a:"are not using",exp:"Negative: are + not + verb-ing. This describes a changing situation."},
      {id:"pc024",type:"fill",q:"The minister ___ (meet) with health officials this morning to discuss the pandemic response.",a:"is meeting",exp:"Future arrangement (planned meeting). Singular subject takes 'is'."},
      {id:"pc025",type:"fill",q:"Unemployment rates ___ (fall) gradually as the economy strengthens.",a:"are falling",exp:"Developing trend. Plural 'rates' takes 'are'."},
      {id:"pc026",type:"mc",q:"Which sentence correctly uses the present continuous?",options:["She is studies for her exam right now.","She is studying for her exam right now.","She studying for her exam right now.","She does studying for her exam right now."],a:1,exp:"Present continuous: subject + is/am/are + verb-ing. 'She is studying' is correct."},
      {id:"pc027",type:"mc",q:"Choose the correct form: 'The number of online learners ___ rapidly.'",options:["is increasing","are increasing","increases","increasing"],a:0,exp:"'The number of' is singular, requiring 'is'. Present continuous for a developing trend."},
      {id:"pc028",type:"mc",q:"Which sentence describes a temporary situation?",options:["She works at the hospital.","She is working at the hospital this month.","She has worked at the hospital.","She worked at the hospital."],a:1,exp:"Present continuous + time phrase 'this month' = temporary situation. Simple present would mean permanent."},
      {id:"pc029",type:"mc",q:"Select the correct negative form: 'They ___ the new curriculum this term.'",options:["are not following","is not following","do not following","not following"],a:0,exp:"Plural 'they' takes 'are not' + verb-ing for negative present continuous."},
      {id:"pc030",type:"mc",q:"Which verb CANNOT be used in the continuous form?",options:["study","belong","develop","increase"],a:1,exp:"'Belong' is a stative verb (possession) and is not normally used in continuous tenses."},
      {id:"pc031",type:"mc",q:"Choose the sentence that expresses an annoying habit:",options:["He always arrives late.","He is always arriving late.","He has always arrived late.","He always arrived late."],a:1,exp:"'Always' + present continuous expresses irritation about a repeated behaviour."},
      {id:"pc032",type:"mc",q:"Which is correct for a future arrangement? 'We ___ the minister tomorrow afternoon.'",options:["meet","are meeting","will meeting","meets"],a:1,exp:"Present continuous is used for definite future arrangements: 'are meeting'."},
      {id:"pc033",type:"mc",q:"Select the correct question form:",options:["Is the university expanding its campus?","Does the university expanding its campus?","Is the university expand its campus?","Are the university expanding its campus?"],a:0,exp:"Question form: Is + singular subject + verb-ing? 'Is the university expanding' is correct."},
      {id:"pc034",type:"mc",q:"Which stative verb is incorrectly used in the continuous?",options:["I am thinking about the problem.","She is having lunch now.","He is knowing the answer.","They are looking at the data."],a:2,exp:"'Know' is a stative verb (mental state) and cannot be used in continuous: 'He knows the answer.'"},
      {id:"pc035",type:"mc",q:"Choose the correct option: 'At present, many countries ___ their immigration policies.'",options:["revise","are revising","revised","has revised"],a:1,exp:"'At present' signals a current ongoing action, requiring present continuous: 'are revising'."},
      {id:"pc036",type:"mc",q:"Which pair correctly distinguishes permanent vs temporary?",options:["She lives in Melbourne. / She is living in Brisbane for the semester.","She is living in Melbourne. / She lives in Brisbane for the semester.","She lives in Melbourne. / She lives in Brisbane for the semester.","She is living in Melbourne. / She is living in Brisbane for the semester."],a:0,exp:"Simple present = permanent home (Melbourne). Present continuous = temporary stay (Brisbane)."},
      {id:"pc037",type:"mc",q:"Select the correct form: 'The researchers ___ (not/collect) data at this stage of the project.'",options:["are not collecting","is not collecting","do not collect","does not collecting"],a:0,exp:"Plural subject + present continuous negative: are not + verb-ing."},
      {id:"pc038",type:"mc",q:"Which sentence describes a trend?",options:["Renewable energy sources produce clean electricity.","Renewable energy is becoming more affordable.","Renewable energy produced clean electricity last year.","Renewable energy has become affordable."],a:1,exp:"Present continuous describes a developing trend: 'is becoming more affordable'."},
      {id:"pc039",type:"mc",q:"Choose the correct form: '___ you ___ to the presentation right now?'",options:["Do / listen","Are / listening","Have / listened","Did / listen"],a:1,exp:"Action happening right now: Are + you + verb-ing?"},
      {id:"pc040",type:"mc",q:"Which sentence has an error?",options:["She is writing her research proposal.","The committee is reviewing the applications.","The students are understanding the new concepts.","We are preparing for the conference."],a:2,exp:"'Understand' is a stative verb and is not normally used in continuous: 'The students understand...'"},
      {id:"pc041",type:"mc",q:"Select the correct option: 'The government ___ new healthcare facilities in rural areas this year.'",options:["builds","is building","has built","building"],a:1,exp:"Current project in progress ('this year') = present continuous. Singular subject takes 'is'."},
      {id:"pc042",type:"mc",q:"Which adverb best fits? 'The company is ___ expanding its operations in Asia.'",options:["always","yesterday","currently","last year"],a:2,exp:"'Currently' is a present-time adverb that works with present continuous."},
      {id:"pc043",type:"mc",q:"Choose the correct form: 'More and more young people ___ higher education.'",options:["pursue","are pursuing","pursues","is pursuing"],a:1,exp:"A growing trend uses present continuous. 'More and more people' is plural: 'are pursuing'."},
      {id:"pc044",type:"mc",q:"Which sentence uses present continuous for a future arrangement?",options:["I am going to study medicine.","I study medicine next year.","I am starting my medical degree in February.","I will study medicine next year."],a:2,exp:"Present continuous + specific future time = definite arrangement: 'am starting in February'."},
      {id:"pc045",type:"mc",q:"Select the error: 'She is seeming very tired after the long shift.'",options:["is seeming","very","after","the long shift"],a:0,exp:"'Seem' is a stative verb and should not be used in continuous: 'She seems very tired...'"},
      {id:"pc046",type:"mc",q:"Which is the correct question? '___ the environmental conditions ___ worse in the region?'",options:["Are / getting","Is / getting","Do / get","Does / get"],a:0,exp:"Plural 'conditions' takes 'Are'. Present continuous for developing situation: Are + getting."},
      {id:"pc047",type:"mc",q:"Choose the correct sentence about a current temporary project:",options:["The team works on the environmental report.","The team is working on the environmental report.","The team has worked on the environmental report.","The team worked on the environmental report."],a:1,exp:"Present continuous for a current temporary project: 'is working on'."},
      {id:"pc048",type:"mc",q:"Which sentence correctly uses 'always' with present continuous?",options:["She always is complaining about deadlines.","She is always complaining about deadlines.","She is complaining always about deadlines.","Always she is complaining about deadlines."],a:1,exp:"Word order: subject + is + always + verb-ing. Expresses an annoying repeated behaviour."},
      {id:"pc049",type:"mc",q:"Select the correct form: 'I ___ a book on environmental economics at the moment.'",options:["read","am reading","reads","have read"],a:1,exp:"'At the moment' signals an action in progress now. First person: 'am reading'."},
      {id:"pc050",type:"mc",q:"Which is NOT a valid use of present continuous?",options:["Describing a scientific fact","Describing an action happening now","Describing a future arrangement","Describing a temporary situation"],a:0,exp:"Scientific facts/general truths use simple present, not present continuous."},
      {id:"pc051",type:"error",q:"She is work on her thesis about climate change at the moment.",a:"She is working on her thesis about climate change at the moment.",exp:"Present continuous requires verb-ing: 'is working', not 'is work'."},
      {id:"pc052",type:"error",q:"The students is preparing for their final examinations this week.",a:"The students are preparing for their final examinations this week.",exp:"Plural subject 'students' requires 'are', not 'is': 'are preparing'."},
      {id:"pc053",type:"error",q:"He is knowing the answer to the research question.",a:"He knows the answer to the research question.",exp:"'Know' is a stative verb and cannot be used in continuous form. Use simple present: 'knows'."},
      {id:"pc054",type:"error",q:"The government are currently build new hospitals in rural areas.",a:"The government is currently building new hospitals in rural areas.",exp:"'Government' (singular) takes 'is'. Continuous requires verb-ing: 'building'."},
      {id:"pc055",type:"error",q:"More and more people is choosing to study online.",a:"More and more people are choosing to study online.",exp:"'People' is plural and requires 'are': 'are choosing'."},
      {id:"pc056",type:"error",q:"I am not understanding why the experiment failed.",a:"I do not understand why the experiment failed.",exp:"'Understand' is a stative verb. Use simple present: 'do not understand'."},
      {id:"pc057",type:"error",q:"The researchers currently analysing the data from the clinical trial.",a:"The researchers are currently analysing the data from the clinical trial.",exp:"Missing auxiliary verb 'are'. Present continuous requires subject + are + verb-ing."},
      {id:"pc058",type:"error",q:"She is always forget to submit her assignments on time.",a:"She is always forgetting to submit her assignments on time.",exp:"Always + present continuous (annoying habit) requires verb-ing: 'is always forgetting'."},
      {id:"pc059",type:"error",q:"Does the university is expanding its research facilities?",a:"Is the university expanding its research facilities?",exp:"Present continuous question: Is + subject + verb-ing? Do not mix 'does' with continuous form."},
      {id:"pc060",type:"error",q:"The patient is not recover as quickly as the doctors expected.",a:"The patient is not recovering as quickly as the doctors expected.",exp:"Negative present continuous: is + not + verb-ing. 'Recovering' is the correct form."},
      {id:"pc061",type:"error",q:"Technology is rapid transforming the education sector.",a:"Technology is rapidly transforming the education sector.",exp:"Adverbs of manner take -ly form: 'rapidly', not 'rapid'."},
      {id:"pc062",type:"error",q:"We are meet the project supervisor tomorrow morning.",a:"We are meeting the project supervisor tomorrow morning.",exp:"Present continuous requires verb-ing: 'are meeting'. This is a future arrangement."},
      {id:"pc063",type:"error",q:"The levels of air pollution in the city is increasing alarmingly.",a:"The levels of air pollution in the city are increasing alarmingly.",exp:"Subject 'levels' is plural, requiring 'are': 'are increasing'."},
      {id:"pc064",type:"error",q:"She is seeming tired after working on the project all day.",a:"She seems tired after working on the project all day.",exp:"'Seem' is a stative verb and should not be used in continuous. Use simple present: 'seems'."},
      {id:"pc065",type:"error",q:"The government is not take adequate measures to address housing affordability.",a:"The government is not taking adequate measures to address housing affordability.",exp:"Present continuous negative requires verb-ing: 'is not taking'."},
      {id:"pc066",type:"error",q:"Are the committee discussing the new policy right now?",a:"Is the committee discussing the new policy right now?",exp:"'The committee' is treated as singular in formal English, requiring 'Is'."},
      {id:"pc067",type:"error",q:"He is believing that online education is superior to traditional methods.",a:"He believes that online education is superior to traditional methods.",exp:"'Believe' is a stative verb. Use simple present: 'believes'."},
      {id:"pc068",type:"error",q:"The children is playing in the new community park this afternoon.",a:"The children are playing in the new community park this afternoon.",exp:"'Children' is plural, requiring 'are': 'are playing'."},
      {id:"pc069",type:"error",q:"The hospital currently is not admitting new patients due to overcrowding.",a:"The hospital is currently not admitting new patients due to overcrowding.",exp:"Correct word order: subject + is + currently + not + verb-ing. Or: is not currently admitting."},
      {id:"pc070",type:"error",q:"At the moment, he is owning three properties in Sydney.",a:"At the moment, he owns three properties in Sydney.",exp:"'Own' is a stative verb (possession) and cannot be used in continuous. Use simple present."},
      {id:"pc071",type:"transform",q:"The government builds new schools in rural areas. [Change to present continuous — current project]",a:"The government is building new schools in rural areas.",exp:"Change simple present to present continuous to emphasise the action is in progress now."},
      {id:"pc072",type:"transform",q:"She studies environmental science. [Rewrite as a temporary situation using present continuous]",a:"She is studying environmental science this semester.",exp:"Add a time expression ('this semester') and use is + verb-ing for a temporary situation."},
      {id:"pc073",type:"transform",q:"The researchers are conducting a large-scale survey. [Make negative]",a:"The researchers are not conducting a large-scale survey.",exp:"Negative present continuous: subject + are + not + verb-ing."},
      {id:"pc074",type:"transform",q:"Is the university expanding its campus? [Change to a statement]",a:"The university is expanding its campus.",exp:"Remove inversion: subject + is + verb-ing."},
      {id:"pc075",type:"transform",q:"They have a meeting with the dean tomorrow. [Rewrite using present continuous for a future arrangement]",a:"They are meeting with the dean tomorrow.",exp:"Present continuous for definite future arrangements: are + verb-ing + future time."},
      {id:"pc076",type:"transform",q:"Air quality improves in the region. [Rewrite as a developing trend with present continuous]",a:"Air quality is improving in the region.",exp:"Present continuous for changing/developing situations: is + verb-ing."},
      {id:"pc077",type:"transform",q:"The company is not investing in renewable energy. [Make affirmative]",a:"The company is investing in renewable energy.",exp:"Remove 'not' from the present continuous structure: is + verb-ing."},
      {id:"pc078",type:"transform",q:"She works from home. She teaches online courses. [Combine using 'and' in present continuous]",a:"She is working from home and teaching online courses.",exp:"Combine two present continuous actions. The second verb-ing does not repeat the auxiliary."},
      {id:"pc079",type:"transform",q:"More people choose public transport. [Rewrite as a current trend]",a:"More and more people are choosing public transport.",exp:"Use 'more and more' + present continuous to express a growing trend."},
      {id:"pc080",type:"transform",q:"The professor reviews the student proposals at the moment. [Correct the tense]",a:"The professor is reviewing the student proposals at the moment.",exp:"'At the moment' requires present continuous, not simple present: is + reviewing."},
      {id:"pc081",type:"transform",q:"The economy is growing steadily. [Make into a question]",a:"Is the economy growing steadily?",exp:"Invert subject and auxiliary: Is + subject + verb-ing?"},
      {id:"pc082",type:"transform",q:"She always complains about the timetable. [Rewrite to show irritation using present continuous]",a:"She is always complaining about the timetable.",exp:"'Always' + present continuous expresses annoyance or irritation about a repeated behaviour."},
      {id:"pc083",type:"transform",q:"We are organising a community health fair next month. [Make into a negative question]",a:"Aren't we organising a community health fair next month?",exp:"Negative question: Aren't + subject + verb-ing? Australian spelling: organising."},
      {id:"pc084",type:"transform",q:"The students are not participating in the research project. [Make affirmative and add 'actively']",a:"The students are actively participating in the research project.",exp:"Remove 'not' and add the adverb 'actively' between 'are' and 'verb-ing'."},
      {id:"pc085",type:"transform",q:"The rate of deforestation increases every year. [Rewrite as a present continuous trend]",a:"The rate of deforestation is increasing year by year.",exp:"Use present continuous for a developing trend: is increasing. 'Year by year' emphasises gradual change."}
    ]
  },
  {
    id: "present-perfect",
    name: "Present Perfect",
    formula: "Subject + have/has + past participle",
    negFormula: "Subject + have/has + not + past participle",
    qFormula: "Have/Has + subject + past participle?",
    usage: ["Life experiences","Actions with present relevance","Unfinished time periods","Recent completions","With since/for durations"],
    signalWords: ["already","yet","just","ever","never","so far","recently","since","for","up to now","lately"],
    examples: {pos:"She has completed her assignment.",neg:"She has not completed her assignment.",q:"Has she completed her assignment?"},
    exercises: [
      {id:"pp001",type:"fill",q:"The government ___ (introduce) several new education policies since 2020.",a:"has introduced",exp:"Singular subject 'government' takes 'has'. 'Since 2020' signals present perfect (action with present relevance)."},
      {id:"pp002",type:"fill",q:"Researchers ___ (discover) a strong link between diet and mental health.",a:"have discovered",exp:"Plural subject 'researchers' takes 'have'. Recent discovery with present relevance."},
      {id:"pp003",type:"fill",q:"She ___ (not/finish) her thesis yet.",a:"has not finished",exp:"Negative present perfect: has + not + past participle. 'Yet' signals an action expected but not completed."},
      {id:"pp004",type:"fill",q:"Technology ___ (change) the way we access information dramatically.",a:"has changed",exp:"Singular 'technology' takes 'has'. The change has present relevance (we still experience its effects)."},
      {id:"pp005",type:"fill",q:"Many countries ___ (adopt) renewable energy targets in recent years.",a:"have adopted",exp:"Plural 'countries' takes 'have'. 'In recent years' signals an unfinished time period."},
      {id:"pp006",type:"fill",q:"The university ___ (already/announce) the results of the scholarship programme.",a:"has already announced",exp:"'Already' goes between 'has' and the past participle: has already announced."},
      {id:"pp007",type:"fill",q:"I ___ (never/visit) a country where English is the primary language.",a:"have never visited",exp:"'Never' goes between 'have' and past participle. Life experience use of present perfect."},
      {id:"pp008",type:"fill",q:"Air quality in the city ___ (improve) significantly since the new regulations were introduced.",a:"has improved",exp:"Singular 'air quality' takes 'has'. 'Since' signals a duration starting in the past and continuing to now."},
      {id:"pp009",type:"fill",q:"The team ___ (just/complete) the environmental impact assessment.",a:"has just completed",exp:"'Just' signals a very recent completion. Goes between has/have and past participle."},
      {id:"pp010",type:"fill",q:"Students ___ (submit) over 200 applications for the exchange programme so far.",a:"have submitted",exp:"Plural 'students' takes 'have'. 'So far' signals an unfinished time period."},
      {id:"pp011",type:"fill",q:"The organisation ___ (not/release) the official report yet.",a:"has not released",exp:"Negative: has + not + past participle. 'Yet' at the end reinforces the incomplete action."},
      {id:"pp012",type:"fill",q:"Healthcare costs ___ (rise) by 15 per cent since last year.",a:"have risen",exp:"Plural 'costs' takes 'have'. 'Risen' is the irregular past participle of 'rise'. 'Since' signals present perfect."},
      {id:"pp013",type:"fill",q:"The professor ___ (publish) three peer-reviewed articles this semester.",a:"has published",exp:"Singular 'professor' takes 'has'. 'This semester' is an unfinished time period."},
      {id:"pp014",type:"fill",q:"We ___ (not/receive) any response from the ethics committee.",a:"have not received",exp:"Negative with plural 'we': have + not + past participle."},
      {id:"pp015",type:"fill",q:"___ you ever ___ (attend) an international academic conference?",a:"Have ... attended",exp:"Question about life experience: Have + subject + ever + past participle?"},
      {id:"pp016",type:"fill",q:"The government ___ (invest) heavily in public health infrastructure for the past decade.",a:"has invested",exp:"'For the past decade' signals a duration. Singular subject takes 'has'."},
      {id:"pp017",type:"fill",q:"Unemployment ___ (decrease) steadily since the economic reforms were implemented.",a:"has decreased",exp:"Singular uncountable 'unemployment' takes 'has'. 'Since' signals present perfect."},
      {id:"pp018",type:"fill",q:"Several studies ___ (show) that bilingual education ___ (have) long-term cognitive benefits.",a:"have shown ... has",exp:"'Studies' (plural) takes 'have shown'. 'Education' (singular) takes 'has'. Second clause is a general truth."},
      {id:"pp019",type:"fill",q:"The school ___ (recently/implement) a new anti-bullying programme.",a:"has recently implemented",exp:"'Recently' goes between has and past participle. Australian spelling: programme."},
      {id:"pp020",type:"fill",q:"They ___ (live) in Australia for over ten years.",a:"have lived",exp:"'For over ten years' signals a duration continuing to the present. Plural takes 'have'."},
      {id:"pp021",type:"fill",q:"The committee ___ (not/yet/reach) a consensus on the proposed changes.",a:"has not yet reached",exp:"'Not yet' goes between has and past participle: has not yet reached."},
      {id:"pp022",type:"fill",q:"Global temperatures ___ (increase) by 1.1 degrees Celsius since pre-industrial times.",a:"have increased",exp:"Plural 'temperatures' takes 'have'. 'Since' signals a duration from past to present."},
      {id:"pp023",type:"fill",q:"She ___ (gain) valuable experience through her volunteer work at the hospital.",a:"has gained",exp:"Singular 'she' takes 'has'. The experience has present relevance."},
      {id:"pp024",type:"fill",q:"The number of people seeking mental health support ___ (grow) considerably lately.",a:"has grown",exp:"'The number of' is singular: 'has'. 'Grown' is the irregular past participle. 'Lately' signals present perfect."},
      {id:"pp025",type:"fill",q:"___ the researchers ___ (analyse) all the data from the trial yet?",a:"Have ... analysed",exp:"Question form: Have + plural subject + past participle? 'Yet' at end signals expectation. Australian spelling: analysed."},
      {id:"pp026",type:"mc",q:"Which sentence correctly uses the present perfect?",options:["She has went to three conferences this year.","She has gone to three conferences this year.","She have gone to three conferences this year.","She has go to three conferences this year."],a:1,exp:"Has + past participle. 'Gone' is the past participle of 'go' (not 'went', which is simple past)."},
      {id:"pp027",type:"mc",q:"Choose the correct option: 'They ___ in this city ___ 2015.'",options:["have lived / since","have lived / for","lived / since","has lived / since"],a:0,exp:"'Since 2015' (specific point in time) + present perfect. Plural 'they' takes 'have'."},
      {id:"pp028",type:"mc",q:"Which signal word requires present perfect?",options:["yesterday","last month","already","in 2019"],a:2,exp:"'Already' is a present perfect signal word. 'Yesterday', 'last month', and 'in 2019' require simple past."},
      {id:"pp029",type:"mc",q:"Select the correct sentence:",options:["I have saw the documentary about climate change.","I have seen the documentary about climate change.","I have seeing the documentary about climate change.","I seen the documentary about climate change."],a:1,exp:"Present perfect: have + past participle. 'Seen' is the past participle of 'see'."},
      {id:"pp030",type:"mc",q:"Which sentence uses present perfect for an unfinished time period?",options:["She wrote two papers last year.","She has written two papers this year.","She is writing two papers.","She wrote two papers this year."],a:1,exp:"'This year' is an unfinished time period, requiring present perfect: 'has written'."},
      {id:"pp031",type:"mc",q:"Choose the correct negative: 'The government ___ the problem.'",options:["has not addressed","have not addressed","has not address","did not addressed"],a:0,exp:"Singular 'government' + negative present perfect: has + not + past participle 'addressed'."},
      {id:"pp032",type:"mc",q:"'Since' or 'for'? 'She has worked here ___ five years.'",options:["since","for","from","during"],a:1,exp:"'For' is used with durations (five years). 'Since' is used with specific points in time (since 2020)."},
      {id:"pp033",type:"mc",q:"Which sentence correctly uses 'just'?",options:["She just has finished the report.","She has just finished the report.","She has finished just the report.","Just she has finished the report."],a:1,exp:"'Just' goes between has/have and the past participle: has just finished."},
      {id:"pp034",type:"mc",q:"Select the correct question form:",options:["Has ever she visited Australia?","Has she ever visited Australia?","Does she have ever visited Australia?","Did she ever visited Australia?"],a:1,exp:"Present perfect question: Has + subject + ever + past participle?"},
      {id:"pp035",type:"mc",q:"Which is the correct past participle of 'write'?",options:["writed","wrote","written","writing"],a:2,exp:"'Written' is the past participle. 'Wrote' is the simple past form."},
      {id:"pp036",type:"mc",q:"Choose the correct sentence about a life experience:",options:["I have never travel overseas.","I have never travelled overseas.","I never have travelled overseas.","I did never travelled overseas."],a:1,exp:"Life experience: have + never + past participle. 'Travelled' is the correct form (Australian spelling)."},
      {id:"pp037",type:"mc",q:"Why is present perfect used here? 'I have lost my student ID card.'",options:["The action happened at a specific time.","The result is relevant now (I still don't have it).","It describes a habit.","It describes a future plan."],a:1,exp:"Present perfect for past actions with present relevance: the card is still missing."},
      {id:"pp038",type:"mc",q:"Which is correct? 'The researchers ___ their findings in a leading journal.'",options:["has published","have published","have publish","published already"],a:1,exp:"Plural 'researchers' takes 'have' + past participle 'published'."},
      {id:"pp039",type:"mc",q:"Select the correct time expression with present perfect:",options:["I have visited Japan yesterday.","I have visited Japan last week.","I have visited Japan three times.","I have visited Japan in 2019."],a:2,exp:"'Three times' works with present perfect (life experience). Specific past times require simple past."},
      {id:"pp040",type:"mc",q:"Choose the correct option: 'How long ___ she ___ at this university?'",options:["has / taught","have / taught","did / taught","has / teach"],a:0,exp:"Singular 'she' takes 'has'. Question: How long + has + subject + past participle?"},
      {id:"pp041",type:"mc",q:"Which sentence is correct?",options:["The committee has already make their decision.","The committee has already made their decision.","The committee have already made their decision.","The committee has already maked their decision."],a:1,exp:"Singular 'committee' takes 'has'. 'Made' is the correct past participle of 'make'."},
      {id:"pp042",type:"mc",q:"'For' or 'since'? 'The policy has been in place ___ January 2023.'",options:["for","since","from","during"],a:1,exp:"'Since' is used with specific points in time: since January 2023."},
      {id:"pp043",type:"mc",q:"Which is NOT a correct use of present perfect?",options:["She has finished the assignment.","They have lived here since 2018.","He has gone to work yesterday.","We have never visited that museum."],a:2,exp:"'Yesterday' is a specific past time and requires simple past: 'He went to work yesterday.'"},
      {id:"pp044",type:"mc",q:"Choose the correct past participle: 'The temperature has ___ by two degrees.'",options:["rise","rose","risen","rising"],a:2,exp:"Rise-rose-risen. 'Risen' is the past participle used with has/have."},
      {id:"pp045",type:"mc",q:"Which sentence correctly uses 'yet'?",options:["She has yet not finished.","She has not finished yet.","She yet has not finished.","Yet she has not finished."],a:1,exp:"'Yet' typically goes at the end of negative sentences: has not finished yet."},
      {id:"pp046",type:"mc",q:"Select the correct form: 'Up to now, the project ___ on schedule.'",options:["remained","has remained","is remaining","remains"],a:1,exp:"'Up to now' signals present perfect: has + past participle."},
      {id:"pp047",type:"mc",q:"Which pair correctly distinguishes simple past vs present perfect?",options:["I saw the film yesterday. / I have seen the film already.","I have saw the film yesterday. / I seen the film already.","I saw the film already. / I have seen the film yesterday.","I have seen the film yesterday. / I saw the film already."],a:0,exp:"Simple past + specific time (yesterday). Present perfect + 'already' (no specific time, present relevance)."},
      {id:"pp048",type:"mc",q:"Choose the correct form: 'The standard of healthcare ___ considerably since the reforms.'",options:["improve","has improved","have improved","improving"],a:1,exp:"Singular 'standard' takes 'has'. 'Since the reforms' signals present perfect."},
      {id:"pp049",type:"mc",q:"Which sentence has correct word order?",options:["She already has submitted her application.","She has already submitted her application.","She has submitted already her application.","Already she has submitted her application."],a:1,exp:"Correct order: subject + has + already + past participle."},
      {id:"pp050",type:"mc",q:"Select the correct option: '___ there ___ any significant changes to the curriculum recently?'",options:["Has / been","Have / been","Did / been","Were / been"],a:1,exp:"'Changes' is plural, requiring 'Have'. Question: Have + there + been + noun?"},
      {id:"pp051",type:"error",q:"She has went to the library to study for her exam.",a:"She has gone to the library to study for her exam.",exp:"'Went' is simple past. The past participle of 'go' is 'gone': has gone."},
      {id:"pp052",type:"error",q:"The students has completed the group project ahead of schedule.",a:"The students have completed the group project ahead of schedule.",exp:"Plural 'students' requires 'have', not 'has': have completed."},
      {id:"pp053",type:"error",q:"He have lived in Sydney since five years.",a:"He has lived in Sydney for five years.",exp:"Two errors: singular 'he' takes 'has'. Durations use 'for' (five years), not 'since' (specific point)."},
      {id:"pp054",type:"error",q:"I have visited the Great Barrier Reef last summer.",a:"I visited the Great Barrier Reef last summer.",exp:"'Last summer' is a specific past time requiring simple past: 'visited'. Present perfect cannot be used with specific past times."},
      {id:"pp055",type:"error",q:"The government has not yet release the annual budget report.",a:"The government has not yet released the annual budget report.",exp:"Present perfect requires past participle: 'released', not base form 'release'."},
      {id:"pp056",type:"error",q:"Researchers have recently discover a new species of coral on the reef.",a:"Researchers have recently discovered a new species of coral on the reef.",exp:"Present perfect requires past participle: 'discovered', not base form 'discover'."},
      {id:"pp057",type:"error",q:"She has already wrote three essays for the assessment this semester.",a:"She has already written three essays for the assessment this semester.",exp:"'Wrote' is simple past. The past participle of 'write' is 'written': has written."},
      {id:"pp058",type:"error",q:"The number of enrolments have increased significantly this year.",a:"The number of enrolments has increased significantly this year.",exp:"'The number of' is singular, requiring 'has'. (Compare: 'A number of enrolments have...')"},
      {id:"pp059",type:"error",q:"Have you ever went to an international conference on climate change?",a:"Have you ever gone to an international conference on climate change?",exp:"Past participle of 'go' is 'gone', not 'went': Have you ever gone...?"},
      {id:"pp060",type:"error",q:"The organisation have not recognised the contributions of volunteer workers.",a:"The organisation has not recognised the contributions of volunteer workers.",exp:"Singular 'organisation' takes 'has'. Australian spelling: organisation, recognised."},
      {id:"pp061",type:"error",q:"Many developing countries has made significant progress in reducing poverty.",a:"Many developing countries have made significant progress in reducing poverty.",exp:"Plural 'countries' requires 'have', not 'has': have made."},
      {id:"pp062",type:"error",q:"She has studied English since three years.",a:"She has studied English for three years.",exp:"Durations use 'for' (three years), not 'since'. 'Since' needs a point in time (since 2023)."},
      {id:"pp063",type:"error",q:"The patient condition has improve since the treatment began.",a:"The patient's condition has improved since the treatment began.",exp:"Two errors: possessive needs apostrophe ('patient's'). Past participle: 'improved', not 'improve'."},
      {id:"pp064",type:"error",q:"They have builded a new research facility on the campus.",a:"They have built a new research facility on the campus.",exp:"'Built' is the correct past participle of 'build'. 'Builded' does not exist in English."},
      {id:"pp065",type:"error",q:"The professor has gave the students detailed instructions for the assignment.",a:"The professor has given the students detailed instructions for the assignment.",exp:"'Gave' is simple past. Past participle of 'give' is 'given': has given."},
      {id:"pp066",type:"error",q:"We did not have finished analysing all the survey responses yet.",a:"We have not finished analysing all the survey responses yet.",exp:"Present perfect negative: have + not + past participle. Do not use 'did' with present perfect."},
      {id:"pp067",type:"error",q:"The cost of living has rose dramatically in major Australian cities.",a:"The cost of living has risen dramatically in major Australian cities.",exp:"'Rose' is simple past. Past participle of 'rise' is 'risen': has risen."},
      {id:"pp068",type:"error",q:"Technology has rapid evolved over the past two decades.",a:"Technology has rapidly evolved over the past two decades.",exp:"Adverb form requires -ly: 'rapidly', not 'rapid'. Has + rapidly + past participle."},
      {id:"pp069",type:"error",q:"The school have recently been awarded a grant for STEM education programmes.",a:"The school has recently been awarded a grant for STEM education programmes.",exp:"Singular 'school' takes 'has'. Australian spelling: programmes."},
      {id:"pp070",type:"error",q:"Up to now, the experiment has produce no significant results.",a:"Up to now, the experiment has produced no significant results.",exp:"Present perfect requires past participle: 'produced', not base form 'produce'."},
      {id:"pp071",type:"transform",q:"The government introduced new environmental laws in 2021. [Rewrite with present perfect — present relevance]",a:"The government has introduced new environmental laws.",exp:"Remove the specific past time. Present perfect emphasises that the laws are still relevant now."},
      {id:"pp072",type:"transform",q:"She completed her PhD. [Add 'just' to show recent completion]",a:"She has just completed her PhD.",exp:"Present perfect with 'just': has + just + past participle."},
      {id:"pp073",type:"transform",q:"They have conducted extensive research on the topic. [Make negative]",a:"They have not conducted extensive research on the topic.",exp:"Negative: have + not + past participle."},
      {id:"pp074",type:"transform",q:"Has the committee approved the new policy? [Change to a statement]",a:"The committee has approved the new policy.",exp:"Remove inversion: subject + has + past participle."},
      {id:"pp075",type:"transform",q:"The organisation started this programme five years ago. [Rewrite with 'for' using present perfect]",a:"The organisation has run this programme for five years.",exp:"Present perfect with 'for' + duration. The programme is still running."},
      {id:"pp076",type:"transform",q:"She has not submitted her application yet. [Make affirmative with 'already']",a:"She has already submitted her application.",exp:"Replace 'not...yet' with 'already' between has and past participle."},
      {id:"pp077",type:"transform",q:"Did you ever visit a developing country? [Correct the tense for a life experience question]",a:"Have you ever visited a developing country?",exp:"Life experience questions use present perfect: Have + subject + ever + past participle?"},
      {id:"pp078",type:"transform",q:"The population of the city grew rapidly. It is now one of the largest in the country. [Combine using present perfect]",a:"The population of the city has grown rapidly and is now one of the largest in the country.",exp:"Present perfect links the past growth to its present result."},
      {id:"pp079",type:"transform",q:"Researchers published 50 papers. The time period is this academic year. [Combine into one sentence]",a:"Researchers have published 50 papers this academic year.",exp:"Unfinished time period ('this academic year') requires present perfect."},
      {id:"pp080",type:"transform",q:"The university has offered online courses since 2018. [Make into a question with 'How long']",a:"How long has the university offered online courses?",exp:"How long + has + subject + past participle? 'Since 2018' answers the question."},
      {id:"pp081",type:"transform",q:"Many governments adopted stricter emissions targets. [Rewrite with 'recently' in present perfect]",a:"Many governments have recently adopted stricter emissions targets.",exp:"Present perfect with 'recently': have + recently + past participle."},
      {id:"pp082",type:"transform",q:"She has never travelled to Europe for an academic conference. [Make affirmative]",a:"She has travelled to Europe for an academic conference.",exp:"Remove 'never'. Has + past participle. Australian spelling: travelled."},
      {id:"pp083",type:"transform",q:"The hospital improved its patient care standards. The improvements continue today. [Combine with present perfect]",a:"The hospital has improved its patient care standards.",exp:"Present perfect shows the improvements started in the past and remain relevant now."},
      {id:"pp084",type:"transform",q:"They have not analysed the results yet. [Rewrite as a question with 'yet']",a:"Have they analysed the results yet?",exp:"Question: Have + subject + past participle + yet? Australian spelling: analysed."},
      {id:"pp085",type:"transform",q:"The cost of education increased. It is still high. [Combine using present perfect to show ongoing relevance]",a:"The cost of education has increased and remains high.",exp:"Present perfect links the past increase to the present situation."}
    ]
  },
  {
    id: "present-perfect-continuous",
    name: "Present Perfect Continuous",
    formula: "Subject + have/has + been + verb-ing",
    negFormula: "Subject + have/has + not + been + verb-ing",
    qFormula: "Have/Has + subject + been + verb-ing?",
    usage: ["Actions continuing to present","Duration emphasis","Explaining current evidence/results","Repeated recent actions"],
    signalWords: ["for","since","all day","all morning","how long","lately","recently"],
    examples: {pos:"She has been studying English for three years.",neg:"She has not been studying long.",q:"Has she been studying English?"},
    exercises: [
      {id:"ppc001",type:"fill",q:"The researchers ___ (work) on this climate study for over five years.",a:"have been working",exp:"Plural subject 'researchers' takes 'have'. 'For over five years' emphasises duration continuing to now."},
      {id:"ppc002",type:"fill",q:"She ___ (study) for the PTE exam since January.",a:"has been studying",exp:"Singular 'she' takes 'has'. 'Since January' signals a continuing action from a specific start point."},
      {id:"ppc003",type:"fill",q:"The government ___ (invest) in healthcare infrastructure since the pandemic began.",a:"has been investing",exp:"Singular 'government' takes 'has'. The investing started in the past and continues now."},
      {id:"ppc004",type:"fill",q:"Students ___ (prepare) for their final exams all week.",a:"have been preparing",exp:"Plural 'students' takes 'have'. 'All week' emphasises the duration of the ongoing preparation."},
      {id:"ppc005",type:"fill",q:"The university ___ (develop) new online courses to meet increasing demand.",a:"has been developing",exp:"Singular 'university' takes 'has'. The development is an ongoing process with recent emphasis."},
      {id:"ppc006",type:"fill",q:"Air quality ___ (decline) steadily in urban areas for the past decade.",a:"has been declining",exp:"Singular 'air quality' takes 'has'. 'For the past decade' shows duration of the ongoing decline."},
      {id:"ppc007",type:"fill",q:"They ___ (not/receive) adequate funding for their research programme lately.",a:"have not been receiving",exp:"Negative: have + not + been + verb-ing. 'Lately' signals recent repeated actions."},
      {id:"ppc008",type:"fill",q:"The professor ___ (teach) at this institution since 2010.",a:"has been teaching",exp:"Singular takes 'has'. 'Since 2010' emphasises the ongoing duration of the teaching."},
      {id:"ppc009",type:"fill",q:"I ___ (read) extensively about environmental policy all semester.",a:"have been reading",exp:"First person takes 'have'. 'All semester' emphasises the duration of the ongoing activity."},
      {id:"ppc010",type:"fill",q:"Healthcare workers ___ (advocate) for better working conditions for years.",a:"have been advocating",exp:"Plural 'workers' takes 'have'. 'For years' emphasises long ongoing duration."},
      {id:"ppc011",type:"fill",q:"The committee ___ (review) applications since early this morning.",a:"has been reviewing",exp:"Singular 'committee' takes 'has'. 'Since early this morning' = specific start point, action continues."},
      {id:"ppc012",type:"fill",q:"Pollution ___ (damage) marine ecosystems for decades.",a:"has been damaging",exp:"Singular uncountable 'pollution' takes 'has'. Emphasises the ongoing, long-term nature of the damage."},
      {id:"ppc013",type:"fill",q:"The population ___ (grow) rapidly, which explains the housing shortage.",a:"has been growing",exp:"Present perfect continuous explains current evidence (housing shortage) through an ongoing process."},
      {id:"ppc014",type:"fill",q:"She ___ (volunteer) at the community health centre since she graduated.",a:"has been volunteering",exp:"Singular takes 'has'. 'Since she graduated' marks the start of an ongoing action."},
      {id:"ppc015",type:"fill",q:"___ you ___ (wait) long for the test results?",a:"Have ... been waiting",exp:"Question form: Have + subject + been + verb-ing? Asks about duration of a current action."},
      {id:"ppc016",type:"fill",q:"The organisation ___ (campaign) for educational reform since its establishment.",a:"has been campaigning",exp:"Singular takes 'has'. The campaigning started at establishment and continues now."},
      {id:"ppc017",type:"fill",q:"Scientists ___ (monitor) sea levels closely for the past thirty years.",a:"have been monitoring",exp:"Plural takes 'have'. 'For the past thirty years' emphasises the long ongoing duration."},
      {id:"ppc018",type:"fill",q:"The patient ___ (recover) well and the doctors are pleased with the progress.",a:"has been recovering",exp:"Current evidence (doctors pleased) explained by an ongoing process (recovering)."},
      {id:"ppc019",type:"fill",q:"He ___ (not/sleep) well lately because of the stress from his studies.",a:"has not been sleeping",exp:"Negative: has + not + been + verb-ing. 'Lately' signals recent repeated actions."},
      {id:"ppc020",type:"fill",q:"Local councils ___ (implement) new recycling programmes across the state.",a:"have been implementing",exp:"Plural 'councils' takes 'have'. Ongoing process across multiple locations. Australian spelling: programmes."},
      {id:"ppc021",type:"fill",q:"The school ___ (try) to improve student attendance rates all year.",a:"has been trying",exp:"Singular takes 'has'. 'All year' emphasises the duration of the ongoing effort."},
      {id:"ppc022",type:"fill",q:"Technology companies ___ (compete) for talent in the artificial intelligence sector.",a:"have been competing",exp:"Plural takes 'have'. Describes an ongoing competitive situation with present relevance."},
      {id:"ppc023",type:"fill",q:"The traffic ___ (get) worse because the city ___ (grow) so quickly.",a:"has been getting ... has been growing",exp:"Both singular subjects take 'has'. Both describe ongoing developing situations."},
      {id:"ppc024",type:"fill",q:"Educators ___ (debate) the effectiveness of standardised testing for decades.",a:"have been debating",exp:"Plural takes 'have'. 'For decades' emphasises the long duration of the ongoing debate."},
      {id:"ppc025",type:"fill",q:"The research team ___ (collect) data since the beginning of the year.",a:"has been collecting",exp:"Singular 'team' takes 'has'. 'Since the beginning of the year' = specific start point."},
      {id:"ppc026",type:"mc",q:"Which sentence correctly uses the present perfect continuous?",options:["She has been study English for two years.","She has been studying English for two years.","She have been studying English for two years.","She has being studying English for two years."],a:1,exp:"Has + been + verb-ing. 'Studying' is the correct -ing form."},
      {id:"ppc027",type:"mc",q:"Choose the correct option: 'How long ___ they ___ on this project?'",options:["have / been working","has / been working","have / working","did / been working"],a:0,exp:"Plural 'they' takes 'have'. Question: How long + have + subject + been + verb-ing?"},
      {id:"ppc028",type:"mc",q:"Which sentence emphasises the DURATION of an action?",options:["She has written three reports.","She has been writing reports all day.","She wrote three reports.","She writes reports every day."],a:1,exp:"Present perfect continuous + 'all day' emphasises the duration. Present perfect simple emphasises completion/result."},
      {id:"ppc029",type:"mc",q:"Select the correct negative form:",options:["He has not been sleeping well lately.","He have not been sleeping well lately.","He has not been sleep well lately.","He not has been sleeping well lately."],a:0,exp:"Singular 'he' + negative: has + not + been + verb-ing."},
      {id:"ppc030",type:"mc",q:"Why is present perfect continuous used here? 'Her eyes are red because she has been crying.'",options:["To describe a habit","To explain current evidence through a recent ongoing action","To describe a completed action","To describe a future plan"],a:1,exp:"Present perfect continuous explains current visible evidence (red eyes) through an ongoing action."},
      {id:"ppc031",type:"mc",q:"Which verb CANNOT be used in present perfect continuous?",options:["work","study","own","teach"],a:2,exp:"'Own' is a stative verb (possession) and cannot be used in continuous: 'has owned', not 'has been owning'."},
      {id:"ppc032",type:"mc",q:"Choose: 'The company ___ employees for the past three months.' (ongoing recruitment)",options:["has hired","has been hiring","hired","hires"],a:1,exp:"Present perfect continuous for an ongoing process over a duration: has been hiring."},
      {id:"ppc033",type:"mc",q:"'Since' or 'for'? 'They have been waiting ___ over an hour.'",options:["since","for","from","during"],a:1,exp:"'For' is used with durations (over an hour). 'Since' is used with specific points in time."},
      {id:"ppc034",type:"mc",q:"Which sentence is about repeated recent actions?",options:["She has been visiting the library every day this week.","She visits the library every day.","She visited the library yesterday.","She has visited the library."],a:0,exp:"Present perfect continuous for repeated recent actions: 'has been visiting every day this week'."},
      {id:"ppc035",type:"mc",q:"Select the correct question form:",options:["Has the government been investing in education?","Has the government been invest in education?","Does the government been investing in education?","Is the government been investing in education?"],a:0,exp:"Question: Has + subject + been + verb-ing?"},
      {id:"ppc036",type:"mc",q:"Which pair correctly distinguishes present perfect vs present perfect continuous?",options:["She has read three books. / She has been reading all afternoon.","She has been reading three books. / She has read all afternoon.","She has read three books. / She has read all afternoon.","She has been reading three books. / She has been reading all afternoon."],a:0,exp:"Present perfect = completed result (three books). Present perfect continuous = duration emphasis (all afternoon)."},
      {id:"ppc037",type:"mc",q:"Choose the correct form: 'The roads are wet. It ___ all morning.'",options:["rained","has rained","has been raining","is raining"],a:2,exp:"Explains current evidence (wet roads) through ongoing action: has been raining."},
      {id:"ppc038",type:"mc",q:"Which is correct? 'The researcher ___ data for the study since March.'",options:["has been collecting","have been collecting","is collecting","collected"],a:0,exp:"Singular 'researcher' takes 'has'. 'Since March' requires present perfect continuous for ongoing action."},
      {id:"ppc039",type:"mc",q:"Select the sentence that describes a temporary ongoing situation:",options:["He works at the hospital.","He has been working at the hospital while they recruit a replacement.","He worked at the hospital.","He has worked at the hospital."],a:1,exp:"Present perfect continuous emphasises a temporary ongoing situation continuing to the present."},
      {id:"ppc040",type:"mc",q:"Which time expression does NOT work with present perfect continuous?",options:["for three hours","since yesterday","all day","last Tuesday"],a:3,exp:"'Last Tuesday' is a specific finished time requiring simple past, not present perfect continuous."},
      {id:"ppc041",type:"mc",q:"Choose the correct option: 'Lately, more students ___ to study environmental science.'",options:["choose","are choosing","have been choosing","chose"],a:2,exp:"'Lately' signals present perfect continuous for repeated recent actions: have been choosing."},
      {id:"ppc042",type:"mc",q:"Why is this sentence wrong? 'She has been knowing the professor for ten years.'",options:["Wrong auxiliary verb","'Know' is stative and cannot be continuous","Wrong time expression","Wrong word order"],a:1,exp:"'Know' is a stative verb. Use present perfect simple: 'She has known the professor for ten years.'"},
      {id:"ppc043",type:"mc",q:"Select the correct form: 'The children ___ (play) outside all afternoon and they look exhausted.'",options:["played","have played","have been playing","are playing"],a:2,exp:"Current evidence (exhausted) explained by ongoing action (all afternoon): have been playing."},
      {id:"ppc044",type:"mc",q:"Which sentence correctly uses present perfect continuous for a developing situation?",options:["Tuition fees increase every year.","Tuition fees have been increasing steadily.","Tuition fees increased last year.","Tuition fees are increasing now."],a:1,exp:"Present perfect continuous for a gradual developing situation continuing to the present."},
      {id:"ppc045",type:"mc",q:"Choose: 'I ___ about changing my research topic.' (recent repeated thought)",options:["think","am thinking","have been thinking","thought"],a:2,exp:"'Think' (= consider) can be used in continuous. Present perfect continuous for recent repeated thoughts."},
      {id:"ppc046",type:"mc",q:"Which is the correct negative question? '___ the team ___ on the report?'",options:["Haven't / been working","Hasn't / been working","Haven't / been work","Doesn't / been working"],a:0,exp:"Plural 'team' in negative question: Haven't + subject + been + verb-ing?"},
      {id:"ppc047",type:"mc",q:"Select the best answer: 'The soil is dry because it ___ for weeks.'",options:["didn't rain","hasn't rained","hasn't been raining","doesn't rain"],a:2,exp:"Explains current evidence (dry soil) through an ongoing absence of rain: hasn't been raining."},
      {id:"ppc048",type:"mc",q:"Which sentence uses present perfect continuous to show cause and effect?",options:["She passed the exam because she studied hard.","She is tired because she has been studying all night.","She studies hard every day.","She will be tired if she studies all night."],a:1,exp:"Present cause (tired) explained by ongoing past-to-present action (has been studying all night)."},
      {id:"ppc049",type:"mc",q:"Choose the correct option: 'The government ___ new trade agreements for several months now.'",options:["negotiates","has negotiated","has been negotiating","negotiated"],a:2,exp:"'For several months now' emphasises ongoing duration: has been negotiating."},
      {id:"ppc050",type:"mc",q:"Which sentence is grammatically correct?",options:["They have been lived here since 2018.","They have been living here since 2018.","They has been living here since 2018.","They have being living here since 2018."],a:1,exp:"Have + been + verb-ing. 'Living' is correct (not 'lived'). 'Have' for plural subject."},
      {id:"ppc051",type:"error",q:"She has been study for the PTE exam since March.",a:"She has been studying for the PTE exam since March.",exp:"Present perfect continuous requires verb-ing: 'been studying', not 'been study'."},
      {id:"ppc052",type:"error",q:"The researchers has been collecting data for the past six months.",a:"The researchers have been collecting data for the past six months.",exp:"Plural 'researchers' requires 'have', not 'has': have been collecting."},
      {id:"ppc053",type:"error",q:"He have been working on his dissertation since last year.",a:"He has been working on his dissertation since last year.",exp:"Singular 'he' requires 'has', not 'have': has been working."},
      {id:"ppc054",type:"error",q:"The government has been investing in education since a long time.",a:"The government has been investing in education for a long time.",exp:"Durations use 'for' (a long time). 'Since' requires a specific point in time."},
      {id:"ppc055",type:"error",q:"The patient has been recover well since the surgery last month.",a:"The patient has been recovering well since the surgery last month.",exp:"Present perfect continuous requires verb-ing: 'been recovering', not 'been recover'."},
      {id:"ppc056",type:"error",q:"They have been knowing each other for twenty years.",a:"They have known each other for twenty years.",exp:"'Know' is stative and cannot be used in continuous. Use present perfect simple: 'have known'."},
      {id:"ppc057",type:"error",q:"The air quality has being declining in the city for the past few years.",a:"The air quality has been declining in the city for the past few years.",exp:"The correct form is 'has been', not 'has being': has been declining."},
      {id:"ppc058",type:"error",q:"She has been working at the hospital since five years.",a:"She has been working at the hospital for five years.",exp:"Durations use 'for' (five years). 'Since' requires a specific time point (since 2020)."},
      {id:"ppc059",type:"error",q:"The students have been prepare for the final exam all week.",a:"The students have been preparing for the final exam all week.",exp:"Present perfect continuous requires verb-ing: 'been preparing'."},
      {id:"ppc060",type:"error",q:"Have the committee been discuss the new admissions policy?",a:"Has the committee been discussing the new admissions policy?",exp:"Singular 'committee' takes 'has'. Continuous requires verb-ing: 'been discussing'."},
      {id:"ppc061",type:"error",q:"I has been reading about environmental sustainability all morning.",a:"I have been reading about environmental sustainability all morning.",exp:"First person 'I' always takes 'have', not 'has': have been reading."},
      {id:"ppc062",type:"error",q:"The company has been hiring new staff since the past three months.",a:"The company has been hiring new staff for the past three months.",exp:"Durations use 'for' (the past three months). 'Since' needs a point in time."},
      {id:"ppc063",type:"error",q:"Scientists has been monitoring the effects of climate change for decades.",a:"Scientists have been monitoring the effects of climate change for decades.",exp:"Plural 'scientists' requires 'have', not 'has': have been monitoring."},
      {id:"ppc064",type:"error",q:"She has been owning that property since 2015.",a:"She has owned that property since 2015.",exp:"'Own' is stative and cannot be continuous. Use present perfect simple: 'has owned'."},
      {id:"ppc065",type:"error",q:"The university has been run exchange programmes since the 1990s.",a:"The university has been running exchange programmes since the 1990s.",exp:"Continuous requires verb-ing: 'been running', not 'been run'. Australian spelling: programmes."},
      {id:"ppc066",type:"error",q:"Technology have been transforming the healthcare industry for years.",a:"Technology has been transforming the healthcare industry for years.",exp:"Singular uncountable 'technology' takes 'has': has been transforming."},
      {id:"ppc067",type:"error",q:"The children have been played in the park all afternoon.",a:"The children have been playing in the park all afternoon.",exp:"Present perfect continuous requires verb-ing: 'been playing', not 'been played'."},
      {id:"ppc068",type:"error",q:"He has not been sleep well because of the noisy construction work nearby.",a:"He has not been sleeping well because of the noisy construction work nearby.",exp:"Continuous requires verb-ing: 'been sleeping', not 'been sleep'."},
      {id:"ppc069",type:"error",q:"The environmental group has been campaigned for cleaner rivers since 2019.",a:"The environmental group has been campaigning for cleaner rivers since 2019.",exp:"Continuous requires verb-ing: 'been campaigning', not 'been campaigned'."},
      {id:"ppc070",type:"error",q:"Local councils have been trying to improved public transport for several years.",a:"Local councils have been trying to improve public transport for several years.",exp:"'Trying to' is followed by base form: 'improve', not 'improved'."},
      {id:"ppc071",type:"transform",q:"She started studying for the PTE exam in January. She is still studying. [Combine using present perfect continuous]",a:"She has been studying for the PTE exam since January.",exp:"Action started in past and continues: has + been + verb-ing + since (point in time)."},
      {id:"ppc072",type:"transform",q:"The researchers have collected data for three months. [Rewrite to emphasise the ongoing duration]",a:"The researchers have been collecting data for three months.",exp:"Change from present perfect (result) to present perfect continuous (duration emphasis)."},
      {id:"ppc073",type:"transform",q:"He has been working overtime every week. [Make negative]",a:"He has not been working overtime every week.",exp:"Negative: has + not + been + verb-ing."},
      {id:"ppc074",type:"transform",q:"Has she been volunteering at the hospital? [Change to a statement]",a:"She has been volunteering at the hospital.",exp:"Remove inversion: subject + has + been + verb-ing."},
      {id:"ppc075",type:"transform",q:"The cost of living is going up. This trend started five years ago. [Combine with present perfect continuous]",a:"The cost of living has been going up for five years.",exp:"Ongoing trend with duration: has + been + verb-ing + for (duration)."},
      {id:"ppc076",type:"transform",q:"They have been debating the policy for months. [Make into a question with 'How long']",a:"How long have they been debating the policy?",exp:"How long + have + subject + been + verb-ing?"},
      {id:"ppc077",type:"transform",q:"The road is wet. It rained recently and may still be raining. [Describe using present perfect continuous]",a:"It has been raining.",exp:"Explains current evidence (wet road) through a recent/ongoing action: has been raining."},
      {id:"ppc078",type:"transform",q:"She has been teaching at the university since 2015. [Rewrite with 'for']",a:"She has been teaching at the university for over ten years.",exp:"Replace 'since 2015' with equivalent duration using 'for'."},
      {id:"ppc079",type:"transform",q:"The students are tired. They studied all day. [Combine to show cause and effect]",a:"The students are tired because they have been studying all day.",exp:"Present perfect continuous explains the current state (tired) through ongoing past action."},
      {id:"ppc080",type:"transform",q:"He has not been attending classes regularly. [Make into a negative question]",a:"Hasn't he been attending classes regularly?",exp:"Negative question: Hasn't + subject + been + verb-ing?"},
      {id:"ppc081",type:"transform",q:"The government invests in renewable energy. This started in 2018 and continues. [Rewrite in present perfect continuous]",a:"The government has been investing in renewable energy since 2018.",exp:"Ongoing action from a specific point: has + been + verb-ing + since."},
      {id:"ppc082",type:"transform",q:"She has been writing her thesis for two years. [Make affirmative into a yes/no question]",a:"Has she been writing her thesis for two years?",exp:"Question: Has + subject + been + verb-ing?"},
      {id:"ppc083",type:"transform",q:"The hospital has been treating more patients lately. [Change to simple present — permanent fact]",a:"The hospital treats many patients.",exp:"Change from present perfect continuous (temporary/recent trend) to simple present (permanent fact)."},
      {id:"ppc084",type:"transform",q:"Scientists monitor ocean temperatures. They started this decades ago. [Combine in present perfect continuous]",a:"Scientists have been monitoring ocean temperatures for decades.",exp:"Ongoing action + duration: have + been + verb-ing + for decades."},
      {id:"ppc085",type:"transform",q:"They have been living in Australia for ten years. [Rewrite with 'since']",a:"They have been living in Australia since 2016.",exp:"Replace 'for ten years' with a specific start point using 'since'."}
    ]
  },
  {
    id: "simple-past",
    name: "Simple Past",
    formula: "Subject + verb-ed (or irregular past form)",
    negFormula: "Subject + did + not + base verb",
    qFormula: "Did + subject + base verb?",
    usage: ["Completed past actions","Past habits","Past states","Sequence of past events","Specific past time"],
    signalWords: ["yesterday","last week","in 2020","ago","when","then","at that time","in the past"],
    examples: {pos:"She studied abroad last year.",neg:"She did not study abroad.",q:"Did she study abroad?"},
    exercises: [
      {id:"spt001",type:"fill",q:"The government ___ (announce) new climate targets last month.",a:"announced",exp:"Completed past action with specific time ('last month'). Regular verb: announce + -d."},
      {id:"spt002",type:"fill",q:"Researchers ___ (publish) their findings in a leading journal in 2023.",a:"published",exp:"Specific past time 'in 2023' requires simple past. Regular verb: publish + -ed."},
      {id:"spt003",type:"fill",q:"She ___ (complete) her degree in environmental science two years ago.",a:"completed",exp:"'Two years ago' signals a completed past action. Regular verb: complete + -d."},
      {id:"spt004",type:"fill",q:"The university ___ (build) a new research facility on campus last year.",a:"built",exp:"Irregular verb: build-built-built. 'Last year' requires simple past."},
      {id:"spt005",type:"fill",q:"The pandemic ___ (force) many educational institutions to adopt online learning.",a:"forced",exp:"Completed past event. Regular verb: force + -d. The pandemic is treated as a past event."},
      {id:"spt006",type:"fill",q:"The committee ___ (not/approve) the proposed changes to the curriculum.",a:"did not approve",exp:"Negative simple past: did + not + base verb. The base form 'approve' follows 'did not'."},
      {id:"spt007",type:"fill",q:"Students ___ (take) the final examination on Friday.",a:"took",exp:"Irregular verb: take-took-taken. Specific past time ('on Friday') requires simple past."},
      {id:"spt008",type:"fill",q:"The organisation ___ (raise) over $2 million for disaster relief last year.",a:"raised",exp:"Specific past time. Regular verb: raise + -d. Note: 'raise' (transitive) vs 'rise' (intransitive)."},
      {id:"spt009",type:"fill",q:"He ___ (write) his thesis on the impact of social media on political engagement.",a:"wrote",exp:"Irregular verb: write-wrote-written. Completed past action."},
      {id:"spt010",type:"fill",q:"The hospital ___ (introduce) a new patient management system in January.",a:"introduced",exp:"Specific past time ('in January'). Regular verb: introduce + -d."},
      {id:"spt011",type:"fill",q:"Many countries ___ (experience) economic downturns during the global financial crisis.",a:"experienced",exp:"Specific past period ('during the global financial crisis'). Regular verb: experience + -d."},
      {id:"spt012",type:"fill",q:"The professor ___ (give) an inspiring lecture on quantum computing yesterday.",a:"gave",exp:"Irregular verb: give-gave-given. 'Yesterday' requires simple past."},
      {id:"spt013",type:"fill",q:"The policy ___ (not/address) the concerns of rural communities at the time.",a:"did not address",exp:"Negative simple past: did + not + base verb. 'At the time' signals a specific past period."},
      {id:"spt014",type:"fill",q:"She ___ (begin) her career in public health after graduating from university.",a:"began",exp:"Irregular verb: begin-began-begun. Sequence of past events."},
      {id:"spt015",type:"fill",q:"The team ___ (conduct) a thorough investigation and ___ (submit) the report.",a:"conducted ... submitted",exp:"Sequence of past events. Both regular verbs: conducted, submitted."},
      {id:"spt016",type:"fill",q:"Climate activists ___ (organise) a major protest in the capital city last Saturday.",a:"organised",exp:"Specific past time. Regular verb. Australian spelling: organised."},
      {id:"spt017",type:"fill",q:"The school ___ (not/meet) the minimum standards set by the education authority.",a:"did not meet",exp:"Negative simple past: did + not + base verb 'meet'. Irregular verb but base form used after 'did'."},
      {id:"spt018",type:"fill",q:"Enrolments ___ (rise) sharply when the university ___ (reduce) tuition fees.",a:"rose ... reduced",exp:"'Rise' is irregular: rise-rose-risen. 'Reduce' is regular: reduced. Past time sequence."},
      {id:"spt019",type:"fill",q:"The researcher ___ (spend) three years collecting data in remote communities.",a:"spent",exp:"Irregular verb: spend-spent-spent. Completed past action with duration."},
      {id:"spt020",type:"fill",q:"The government ___ (cut) funding for the arts programme by 30 per cent in the last budget.",a:"cut",exp:"Irregular verb: cut-cut-cut (no change). 'In the last budget' signals specific past time."},
      {id:"spt021",type:"fill",q:"___ the minister ___ (attend) the international summit on climate change?",a:"Did ... attend",exp:"Question form: Did + subject + base verb? The base form follows 'Did'."},
      {id:"spt022",type:"fill",q:"The earthquake ___ (destroy) hundreds of buildings and ___ (leave) thousands homeless.",a:"destroyed ... left",exp:"Sequence of past events. 'Destroy' is regular; 'leave' is irregular: leave-left-left."},
      {id:"spt023",type:"fill",q:"She ___ (not/realise) the significance of the findings until she reviewed them again.",a:"did not realise",exp:"Negative past: did + not + base verb. Australian spelling: realise."},
      {id:"spt024",type:"fill",q:"The World Health Organisation ___ (declare) the outbreak a global health emergency.",a:"declared",exp:"Completed past action. Regular verb: declare + -d."},
      {id:"spt025",type:"fill",q:"In the past, people ___ (rely) heavily on printed newspapers for information.",a:"relied",exp:"Past habit with 'in the past'. Regular verb: rely → relied (y changes to i before -ed)."},
      {id:"spt026",type:"mc",q:"Which sentence correctly uses the simple past?",options:["She has completed the assignment yesterday.","She completed the assignment yesterday.","She did completed the assignment yesterday.","She was completed the assignment yesterday."],a:1,exp:"Simple past with specific time: subject + past form. 'Completed' is correct. Cannot use 'has' with 'yesterday'."},
      {id:"spt027",type:"mc",q:"Choose the correct past form of 'write':",options:["writed","wrote","written","writing"],a:1,exp:"Irregular verb: write-wrote-written. 'Wrote' is the simple past form."},
      {id:"spt028",type:"mc",q:"Which signal word requires simple past?",options:["already","yet","last Tuesday","since"],a:2,exp:"'Last Tuesday' is a specific past time requiring simple past. The others work with present perfect."},
      {id:"spt029",type:"mc",q:"Select the correct negative: 'The experiment ___ the expected results.'",options:["did not produce","did not produced","does not produced","not produced"],a:0,exp:"Negative simple past: did + not + base verb 'produce'."},
      {id:"spt030",type:"mc",q:"Which sentence describes a sequence of past events?",options:["She arrives and begins working.","She arrived and began working.","She has arrived and has begun working.","She was arriving and was beginning working."],a:1,exp:"Simple past for a sequence: arrived (first), began (second). Both completed actions."},
      {id:"spt031",type:"mc",q:"Choose the correct past form: 'The temperature ___ by 3 degrees last summer.'",options:["rised","rose","risen","raise"],a:1,exp:"Irregular verb: rise-rose-risen. 'Rose' is the simple past form."},
      {id:"spt032",type:"mc",q:"Which question form is correct?",options:["Did the government announced new policies?","Did the government announce new policies?","Does the government announced new policies?","Was the government announce new policies?"],a:1,exp:"Question: Did + subject + base verb? Base form 'announce' follows 'Did'."},
      {id:"spt033",type:"mc",q:"Select the correct sentence:",options:["The researchers finded significant evidence.","The researchers found significant evidence.","The researchers have find significant evidence.","The researchers did found significant evidence."],a:1,exp:"Irregular verb: find-found-found. Simple past: 'found'."},
      {id:"spt034",type:"mc",q:"Which sentence uses simple past for a past habit?",options:["She goes to the library every day.","She used to go to the library every day.","She is going to the library.","She has gone to the library."],a:1,exp:"'Used to' + base verb describes past habits that no longer continue."},
      {id:"spt035",type:"mc",q:"Choose the correct past form of 'teach':",options:["teached","taught","tought","teaching"],a:1,exp:"Irregular verb: teach-taught-taught. 'Taught' is the simple past form."},
      {id:"spt036",type:"mc",q:"Which sentence is grammatically correct?",options:["She didn't went to the conference.","She didn't go to the conference.","She didn't goes to the conference.","She not go to the conference."],a:1,exp:"Negative past: did + not (didn't) + base verb 'go'. Never use past form after 'did'."},
      {id:"spt037",type:"mc",q:"Select the correct option: 'The organisation ___ its goals despite limited resources.'",options:["achieve","achieved","has achieve","achieving"],a:1,exp:"Completed past action requires simple past: 'achieved'."},
      {id:"spt038",type:"mc",q:"Which pair shows correct irregular past forms?",options:["go-goed, see-seed","go-went, see-saw","go-gone, see-seen","go-going, see-seeing"],a:1,exp:"Irregular past forms: go-went, see-saw. The third pair shows past participles, not simple past."},
      {id:"spt039",type:"mc",q:"Choose the correct form: 'When ___ the new environmental legislation ___ into effect?'",options:["did / come","did / came","does / come","has / come"],a:0,exp:"Past question: When + did + subject + base verb? 'Come' (base form) follows 'did'."},
      {id:"spt040",type:"mc",q:"Which sentence is correct?",options:["The population growed rapidly in the 20th century.","The population grew rapidly in the 20th century.","The population grown rapidly in the 20th century.","The population grewed rapidly in the 20th century."],a:1,exp:"Irregular verb: grow-grew-grown. 'Grew' is the simple past form."},
      {id:"spt041",type:"mc",q:"Select the correct sentence about a past state:",options:["She was knowing the answer.","She knew the answer.","She has knew the answer.","She did knew the answer."],a:1,exp:"Past states use simple past: 'knew' (irregular: know-knew-known). Not continuous for stative verbs."},
      {id:"spt042",type:"mc",q:"Which is correct? 'The government ___ the issue and ___ new legislation.'",options:["recognised / introduced","recognised / introduce","recognise / introduced","recognising / introducing"],a:0,exp:"Both verbs in simple past for a sequence: recognised, introduced. Australian spelling: recognised."},
      {id:"spt043",type:"mc",q:"Choose the correct negative question:",options:["Didn't the study show significant results?","Did not the study showed significant results?","Didn't the study showed significant results?","Did the study not shows significant results?"],a:0,exp:"Negative question: Didn't + subject + base verb? 'Show' is the base form after 'Didn't'."},
      {id:"spt044",type:"mc",q:"Select the correct past form of 'lead':",options:["leaded","led","lead","leading"],a:1,exp:"Irregular verb: lead-led-led. Common error: 'leaded' does not exist as past tense of 'lead'."},
      {id:"spt045",type:"mc",q:"Which sentence correctly uses simple past for a specific time?",options:["She has graduated in 2022.","She graduated in 2022.","She is graduated in 2022.","She graduates in 2022."],a:1,exp:"Specific past time 'in 2022' requires simple past: 'graduated'. Cannot use present perfect with a specific past time."},
      {id:"spt046",type:"mc",q:"Choose the correct form: 'The children ___ not ___ the importance of the lesson at that time.'",options:["did / understand","did / understood","do / understand","were / understand"],a:0,exp:"Negative past: did + not + base verb 'understand'. Base form always follows 'did'."},
      {id:"spt047",type:"mc",q:"Which pair of irregular verbs is correct?",options:["begin-begun, choose-chosen","begin-began, choose-chose","begin-beginned, choose-choosed","begin-began, choose-chosen"],a:1,exp:"Simple past: begin-began, choose-chose. 'Begun' and 'chosen' are past participles."},
      {id:"spt048",type:"mc",q:"Select the correct sentence:",options:["The team did not finished the project on time.","The team did not finish the project on time.","The team not did finish the project on time.","The team did not finishes the project on time."],a:1,exp:"Negative: did + not + base verb 'finish'. Never add -ed or -s after 'did not'."},
      {id:"spt049",type:"mc",q:"Which sentence uses simple past for a completed duration?",options:["She lived in London for two years.","She has lived in London for two years.","She is living in London for two years.","She lives in London for two years."],a:0,exp:"Simple past + 'for two years' means the stay is finished. Present perfect would mean she still lives there."},
      {id:"spt050",type:"mc",q:"Choose the correct form: 'The earthquake ___ at 3:47 a.m. and ___ for 45 seconds.'",options:["striked / lasted","struck / lasted","stricken / lasting","strikes / lasts"],a:1,exp:"Irregular: strike-struck-struck. Regular: lasted. Both simple past for completed events."},
      {id:"spt051",type:"error",q:"She did not attended the lecture because she was unwell.",a:"She did not attend the lecture because she was unwell.",exp:"After 'did not', use the base verb: 'attend', not 'attended'. Never double-mark past tense."},
      {id:"spt052",type:"error",q:"The government spended millions on the infrastructure project last year.",a:"The government spent millions on the infrastructure project last year.",exp:"Irregular verb: spend-spent-spent. 'Spended' does not exist."},
      {id:"spt053",type:"error",q:"The researchers have published their findings in a journal in 2021.",a:"The researchers published their findings in a journal in 2021.",exp:"Specific past time 'in 2021' requires simple past. Cannot use present perfect with a specific past time."},
      {id:"spt054",type:"error",q:"He goed to the university to submit his application yesterday.",a:"He went to the university to submit his application yesterday.",exp:"Irregular verb: go-went-gone. 'Goed' does not exist."},
      {id:"spt055",type:"error",q:"The committee did not reached a consensus during the meeting.",a:"The committee did not reach a consensus during the meeting.",exp:"After 'did not', use base verb: 'reach', not 'reached'."},
      {id:"spt056",type:"error",q:"The school builded a new gymnasium for the students last summer.",a:"The school built a new gymnasium for the students last summer.",exp:"Irregular verb: build-built-built. 'Builded' does not exist."},
      {id:"spt057",type:"error",q:"Many people losted their jobs during the economic recession.",a:"Many people lost their jobs during the economic recession.",exp:"Irregular verb: lose-lost-lost. 'Losted' does not exist."},
      {id:"spt058",type:"error",q:"She studyed abroad for one semester before returning to Australia.",a:"She studied abroad for one semester before returning to Australia.",exp:"Spelling rule: when a verb ends in consonant + y, change y to i and add -ed: study → studied."},
      {id:"spt059",type:"error",q:"The organisation did not recognised the need for reform at that time.",a:"The organisation did not recognise the need for reform at that time.",exp:"After 'did not', use base verb: 'recognise'. Australian spelling: recognise."},
      {id:"spt060",type:"error",q:"When did the new policy came into effect?",a:"When did the new policy come into effect?",exp:"After 'did', use base verb: 'come', not 'came'."},
      {id:"spt061",type:"error",q:"The professor teached at three different universities before retiring.",a:"The professor taught at three different universities before retiring.",exp:"Irregular verb: teach-taught-taught. 'Teached' does not exist."},
      {id:"spt062",type:"error",q:"She leaded the research team that discovered the new treatment.",a:"She led the research team that discovered the new treatment.",exp:"Irregular verb: lead-led-led. 'Leaded' does not exist as past tense of 'lead'."},
      {id:"spt063",type:"error",q:"The government cutted funding for environmental protection programmes last year.",a:"The government cut funding for environmental protection programmes last year.",exp:"Irregular verb: cut-cut-cut (no change). 'Cutted' does not exist."},
      {id:"spt064",type:"error",q:"Did the students understood the instructions before the exam began?",a:"Did the students understand the instructions before the exam began?",exp:"After 'Did', use base verb: 'understand', not 'understood'."},
      {id:"spt065",type:"error",q:"The number of applications rised significantly after the scholarship was announced.",a:"The number of applications rose significantly after the scholarship was announced.",exp:"Irregular verb: rise-rose-risen. 'Rised' does not exist."},
      {id:"spt066",type:"error",q:"She choosed to specialise in public health policy after her undergraduate studies.",a:"She chose to specialise in public health policy after her undergraduate studies.",exp:"Irregular verb: choose-chose-chosen. 'Choosed' does not exist."},
      {id:"spt067",type:"error",q:"The city growed rapidly during the industrial revolution and became a major hub.",a:"The city grew rapidly during the industrial revolution and became a major hub.",exp:"Irregular verb: grow-grew-grown. 'Growed' does not exist."},
      {id:"spt068",type:"error",q:"They catched the early train and arrived at the conference on time.",a:"They caught the early train and arrived at the conference on time.",exp:"Irregular verb: catch-caught-caught. 'Catched' does not exist."},
      {id:"spt069",type:"error",q:"The patient feeled much better after the treatment was completed.",a:"The patient felt much better after the treatment was completed.",exp:"Irregular verb: feel-felt-felt. 'Feeled' does not exist."},
      {id:"spt070",type:"error",q:"The new policy effected thousands of residents when it was implemented.",a:"The new policy affected thousands of residents when it was implemented.",exp:"'Affect' (verb: to influence) vs 'effect' (noun: result, or verb: to bring about). Here 'affected' is correct."},
      {id:"spt071",type:"transform",q:"The government introduces new healthcare policies. [Change to simple past with 'last year']",a:"The government introduced new healthcare policies last year.",exp:"Change present to past: add -d to regular verb. Add specific past time marker."},
      {id:"spt072",type:"transform",q:"She wrote her dissertation on sustainable development. [Make negative]",a:"She did not write her dissertation on sustainable development.",exp:"Negative past: did + not + base verb 'write'. The base form replaces the past form."},
      {id:"spt073",type:"transform",q:"The researchers found significant evidence. [Make into a question]",a:"Did the researchers find significant evidence?",exp:"Question: Did + subject + base verb? 'Find' (base form) replaces 'found'."},
      {id:"spt074",type:"transform",q:"Did the committee approve the proposal? [Change to a positive statement]",a:"The committee approved the proposal.",exp:"Remove 'Did' and use the past form of the verb: 'approved'."},
      {id:"spt075",type:"transform",q:"She has studied at three universities. [Change to simple past with a specific time]",a:"She studied at three universities before 2020.",exp:"Remove 'has' and add a past time marker. Simple past for completed actions at specific times."},
      {id:"spt076",type:"transform",q:"The organisation did not support the initiative. [Make into a negative question]",a:"Didn't the organisation support the initiative?",exp:"Negative question: Didn't + subject + base verb?"},
      {id:"spt077",type:"transform",q:"The school builds a new library. [Rewrite as a completed past event]",a:"The school built a new library.",exp:"Change present to past. Irregular verb: build-built-built."},
      {id:"spt078",type:"transform",q:"Many students failed the exam. The university reviewed the assessment criteria. [Combine with 'so']",a:"Many students failed the exam, so the university reviewed the assessment criteria.",exp:"Join two simple past sentences with comma + 'so' (cause and effect)."},
      {id:"spt079",type:"transform",q:"She went to the conference. She presented her research. She networked with colleagues. [Combine as a sequence]",a:"She went to the conference, presented her research, and networked with colleagues.",exp:"List past actions in sequence with commas and 'and' before the last item."},
      {id:"spt080",type:"transform",q:"The city is growing rapidly. [Rewrite as a past state using 'In the 1990s']",a:"In the 1990s, the city grew rapidly.",exp:"Change present continuous to simple past. Irregular: grow-grew-grown. Add past time marker."},
      {id:"spt081",type:"transform",q:"The government spent $5 billion on defence. [Make into a question with 'How much']",a:"How much did the government spend on defence?",exp:"How much + did + subject + base verb? 'Spend' (base form) after 'did'."},
      {id:"spt082",type:"transform",q:"They did not attend the seminar. [Make affirmative]",a:"They attended the seminar.",exp:"Remove 'did not' and use past form of verb: 'attended'."},
      {id:"spt083",type:"transform",q:"The population of the region decreased by 10 per cent. [Make into a yes/no question]",a:"Did the population of the region decrease by 10 per cent?",exp:"Question: Did + subject + base verb? 'Decrease' (base) after 'Did'."},
      {id:"spt084",type:"transform",q:"The teacher explains the topic every day. [Rewrite as a past habit with 'used to']",a:"The teacher used to explain the topic every day.",exp:"'Used to' + base verb for past habits that no longer continue."},
      {id:"spt085",type:"transform",q:"She did not recognise the challenges facing the community. [Make into a question starting with 'Why']",a:"Why did she not recognise the challenges facing the community?",exp:"Why + did + subject + not + base verb? Australian spelling: recognise."}
    ]
  },
  {
    id: "past-continuous",
    name: "Past Continuous",
    formula: "Subject + was/were + verb-ing",
    negFormula: "Subject + was/were + not + verb-ing",
    qFormula: "Was/Were + subject + verb-ing?",
    usage: ["Actions in progress at a past time","Background actions interrupted by another event","Parallel past actions","Setting the scene in narratives"],
    signalWords: ["while","when","as","at that moment","at 8pm yesterday","all day yesterday"],
    examples: {pos:"She was reading when the phone rang.",neg:"She was not reading at that time.",q:"Was she reading when you arrived?"},
    exercises: [
      {id:"ptc001",type:"fill",q:"The professor ___ (deliver) a lecture when the fire alarm went off.",a:"was delivering",exp:"Background action in progress interrupted by a sudden event. Singular subject takes 'was'."},
      {id:"ptc002",type:"fill",q:"Students ___ (study) in the library when the power outage occurred.",a:"were studying",exp:"Plural 'students' takes 'were'. Ongoing action interrupted by a sudden event."},
      {id:"ptc003",type:"fill",q:"The government ___ (negotiate) a new trade agreement at that time.",a:"was negotiating",exp:"Action in progress at a specific past time ('at that time'). Singular takes 'was'."},
      {id:"ptc004",type:"fill",q:"She ___ (write) her research paper while her colleagues ___ (analyse) the data.",a:"was writing ... were analysing",exp:"Two parallel past actions: singular 'she' takes 'was'; plural 'colleagues' takes 'were'. Australian spelling: analysing."},
      {id:"ptc005",type:"fill",q:"The committee ___ (discuss) the budget proposal when the chairman arrived.",a:"was discussing",exp:"Ongoing action (discussing) interrupted by a completed action (arrived). Singular takes 'was'."},
      {id:"ptc006",type:"fill",q:"At 9 p.m. last night, I ___ (review) the latest research on climate change.",a:"was reviewing",exp:"Action in progress at a specific past time. First person singular takes 'was'."},
      {id:"ptc007",type:"fill",q:"The researchers ___ (not/make) any progress because the equipment ___ (malfunction).",a:"were not making ... was malfunctioning",exp:"Negative: were + not + verb-ing. Second clause: singular 'equipment' takes 'was'."},
      {id:"ptc008",type:"fill",q:"While the surgeon ___ (operate), the nurses ___ (monitor) the patient's vital signs.",a:"was operating ... were monitoring",exp:"Parallel actions: singular 'surgeon' = 'was'; plural 'nurses' = 'were'. Connected by 'while'."},
      {id:"ptc009",type:"fill",q:"The hospital ___ (treat) hundreds of patients during the health crisis.",a:"was treating",exp:"Setting the scene: what was happening during a past period. Singular takes 'was'."},
      {id:"ptc010",type:"fill",q:"She ___ (prepare) for the conference presentation all morning yesterday.",a:"was preparing",exp:"'All morning yesterday' signals a continuous action over a past time period."},
      {id:"ptc011",type:"fill",q:"When the announcement was made, thousands of people ___ (watch) the broadcast live.",a:"were watching",exp:"Action in progress at the time of the announcement. Plural takes 'were'."},
      {id:"ptc012",type:"fill",q:"The economy ___ (recover) slowly when the second wave of the pandemic hit.",a:"was recovering",exp:"Background action (recovering) interrupted by a sudden event (pandemic hit). Singular takes 'was'."},
      {id:"ptc013",type:"fill",q:"The children ___ (not/pay) attention while the teacher ___ (explain) the lesson.",a:"were not paying ... was explaining",exp:"Parallel actions: plural 'children' = 'were not paying'; singular 'teacher' = 'was explaining'."},
      {id:"ptc014",type:"fill",q:"At that moment, the team ___ (finalise) the details of the environmental impact report.",a:"was finalising",exp:"'At that moment' signals a specific point in past time. Singular takes 'was'. Australian spelling: finalise."},
      {id:"ptc015",type:"fill",q:"While the students ___ (take) the exam, the invigilator ___ (walk) around the hall.",a:"were taking ... was walking",exp:"Parallel actions connected by 'while'. Plural 'students' = 'were'; singular 'invigilator' = 'was'."},
      {id:"ptc016",type:"fill",q:"The city ___ (experience) rapid urbanisation during the 1990s.",a:"was experiencing",exp:"Setting the scene for a past period. Singular takes 'was'."},
      {id:"ptc017",type:"fill",q:"He ___ (not/listen) to the safety briefing when the accident happened.",a:"was not listening",exp:"Negative: was + not + verb-ing. The ongoing failure to listen led to a consequence."},
      {id:"ptc018",type:"fill",q:"The researchers ___ (collect) samples as the tide ___ (come) in.",a:"were collecting ... was coming",exp:"Parallel actions: plural 'researchers' = 'were'; singular 'tide' = 'was'. Connected by 'as'."},
      {id:"ptc019",type:"fill",q:"At 3 p.m. yesterday, the minister ___ (address) parliament about the education reforms.",a:"was addressing",exp:"Action in progress at a specific past time. Singular takes 'was'."},
      {id:"ptc020",type:"fill",q:"It ___ (rain) heavily, and the streets ___ (flood) across the city.",a:"was raining ... were flooding",exp:"Setting the scene: singular 'it' = 'was raining'; plural 'streets' = 'were flooding'."},
      {id:"ptc021",type:"fill",q:"The university ___ (consider) merging two departments when the dean resigned.",a:"was considering",exp:"Ongoing deliberation interrupted by a sudden event. Singular takes 'was'."},
      {id:"ptc022",type:"fill",q:"While she ___ (conduct) the interview, her assistant ___ (record) the conversation.",a:"was conducting ... was recording",exp:"Two parallel past actions. Both singular subjects take 'was'."},
      {id:"ptc023",type:"fill",q:"The volunteers ___ (distribute) supplies when the storm ___ (begin).",a:"were distributing ... began",exp:"Ongoing action (past continuous) interrupted by a sudden event (simple past). 'Storm' = simple past 'began'."},
      {id:"ptc024",type:"fill",q:"All day yesterday, the technicians ___ (repair) the hospital's ventilation system.",a:"were repairing",exp:"'All day yesterday' signals continuous action over a past period. Plural takes 'were'."},
      {id:"ptc025",type:"fill",q:"The patient ___ (rest) comfortably when the doctor came to check on her.",a:"was resting",exp:"Background action interrupted by another event. Singular takes 'was'."},
      {id:"ptc026",type:"mc",q:"Which sentence correctly uses the past continuous?",options:["She was study when I called.","She was studying when I called.","She were studying when I called.","She studying when I called."],a:1,exp:"Past continuous: was/were + verb-ing. Singular 'she' takes 'was studying'."},
      {id:"ptc027",type:"mc",q:"Choose the correct form: 'While they ___, the lights went out.'",options:["were presenting","was presenting","presented","are presenting"],a:0,exp:"Plural 'they' takes 'were'. Past continuous for the interrupted background action."},
      {id:"ptc028",type:"mc",q:"Which sentence sets the scene in a narrative?",options:["The sun shone brightly.","The sun was shining brightly as the guests arrived.","The sun has been shining brightly.","The sun shines brightly every day."],a:1,exp:"Past continuous sets the background scene: 'was shining' describes the ongoing situation."},
      {id:"ptc029",type:"mc",q:"Select the correct sentence with two parallel actions:",options:["She cooked while he cleaned.","She was cooking while he was cleaning.","She was cooking while he cleaned.","She cooked while he was cleaning."],a:1,exp:"Two simultaneous ongoing actions: both in past continuous, connected by 'while'."},
      {id:"ptc030",type:"mc",q:"Which pair correctly shows interruption? (background + sudden event)",options:["She was reading / the phone rang","She read / the phone was ringing","She was reading / the phone was ringing","She read / the phone rang"],a:0,exp:"Background action (past continuous: was reading) interrupted by sudden event (simple past: rang)."},
      {id:"ptc031",type:"mc",q:"Choose the correct negative: 'The students ___ attention during the lecture.'",options:["were not paying","was not paying","did not paying","not were paying"],a:0,exp:"Plural 'students' + negative past continuous: were + not + verb-ing."},
      {id:"ptc032",type:"mc",q:"Which question form is correct?",options:["Were the researchers collecting data at that time?","Was the researchers collecting data at that time?","Did the researchers collecting data at that time?","Were the researchers collect data at that time?"],a:0,exp:"Question: Were + plural subject + verb-ing? 'Were the researchers collecting' is correct."},
      {id:"ptc033",type:"mc",q:"Select the sentence that describes an action in progress at a specific past time:",options:["At 10 a.m., she finished the report.","At 10 a.m., she was finishing the report.","At 10 a.m., she has finished the report.","At 10 a.m., she finishes the report."],a:1,exp:"At a specific past time + past continuous = action in progress at that moment."},
      {id:"ptc034",type:"mc",q:"Which is correct? 'When the earthquake struck, people ___.'",options:["slept","were sleeping","have slept","are sleeping"],a:1,exp:"Past continuous for the ongoing action at the moment the earthquake struck."},
      {id:"ptc035",type:"mc",q:"Choose the correct connective: '___ the professor was lecturing, a student asked a question.'",options:["While","During","For","Since"],a:0,exp:"'While' connects two clauses (past continuous + simple past). 'During' needs a noun, not a clause."},
      {id:"ptc036",type:"mc",q:"Which sentence is grammatically correct?",options:["He was writting his assignment all evening.","He was writing his assignment all evening.","He was writeing his assignment all evening.","He was writed his assignment all evening."],a:1,exp:"Spelling: write → writing (drop the silent -e before -ing). 'Writing' is correct."},
      {id:"ptc037",type:"mc",q:"Select the correct use of past continuous for scene-setting:",options:["It rained and the wind blew hard.","It was raining and the wind was blowing hard.","It has rained and the wind has blown hard.","It rains and the wind blows hard."],a:1,exp:"Past continuous for setting the scene in narratives: 'was raining', 'was blowing'."},
      {id:"ptc038",type:"mc",q:"Which sentence shows an interrupted action?",options:["She ate dinner and watched TV.","She was eating dinner when the doorbell rang.","She has been eating dinner.","She eats dinner every evening."],a:1,exp:"Past continuous (ongoing) interrupted by simple past (sudden): 'was eating... when... rang'."},
      {id:"ptc039",type:"mc",q:"Choose the correct form: 'The government ___ the new policy when criticism began.'",options:["was implementing","were implementing","implemented","has implemented"],a:0,exp:"Singular 'government' + past continuous for interrupted action: 'was implementing'."},
      {id:"ptc040",type:"mc",q:"Which stative verb should NOT be in past continuous?",options:["She was knowing the answer when I asked.","She was walking to the library when I called.","The students were discussing the assignment.","The professor was explaining the theory."],a:0,exp:"'Know' is stative and cannot be continuous. Correct: 'She knew the answer when I asked.'"},
      {id:"ptc041",type:"mc",q:"Select the correct sentence:",options:["While I was studied, my phone rang.","While I was studying, my phone rang.","While I studying, my phone rang.","While I did study, my phone rang."],a:1,exp:"Past continuous: was + verb-ing. 'While I was studying' is correct."},
      {id:"ptc042",type:"mc",q:"Which sentence correctly uses 'as' with past continuous?",options:["As she walked home, she noticed the new building.","As she was walking home, she noticed the new building.","As she has walked home, she noticed the new building.","As she walks home, she noticed the new building."],a:1,exp:"'As' + past continuous for background action: 'As she was walking home...'"},
      {id:"ptc043",type:"mc",q:"Choose the correct pair: Background action + interruption:",options:["The children played / the bell rang","The children were playing / the bell rang","The children played / the bell was ringing","The children were playing / the bell was ringing"],a:1,exp:"Past continuous (background: were playing) + simple past (interruption: rang)."},
      {id:"ptc044",type:"mc",q:"Which is the correct question? '___ he ___ when the accident occurred?'",options:["Was / driving","Were / driving","Did / driving","Was / driven"],a:0,exp:"Singular 'he' + past continuous question: Was + subject + verb-ing?"},
      {id:"ptc045",type:"mc",q:"Select the sentence with correct subject-verb agreement:",options:["The team was preparing for the presentation.","The team were preparing for the presentation.","Both A and B are acceptable.","Neither is correct."],a:2,exp:"'Team' can take singular 'was' (formal) or plural 'were' (informal/British). Both are acceptable."},
      {id:"ptc046",type:"mc",q:"Which time expression works best with past continuous?",options:["yesterday","last week","at 6 o'clock yesterday evening","in 2020"],a:2,exp:"'At 6 o'clock yesterday evening' = specific moment in the past, ideal for past continuous."},
      {id:"ptc047",type:"mc",q:"Choose the correct form: 'They ___ quietly in the waiting room when the nurse called their names.'",options:["sat","were sitting","have sat","are sitting"],a:1,exp:"Ongoing action at the moment the nurse called: past continuous 'were sitting'."},
      {id:"ptc048",type:"mc",q:"Which sentence has a grammatical error?",options:["She was writing while he was reading.","They were discussing the results at that time.","The professor was knowing the student very well.","We were working on the project all afternoon."],a:2,exp:"'Know' is stative: cannot use past continuous. Correct: 'The professor knew the student very well.'"},
      {id:"ptc049",type:"mc",q:"Select the correct negative question:",options:["Wasn't the hospital treating patients during the crisis?","Were not the hospital treating patients during the crisis?","Didn't the hospital was treating patients during the crisis?","Wasn't the hospital treated patients during the crisis?"],a:0,exp:"Negative question: Wasn't + singular subject + verb-ing?"},
      {id:"ptc050",type:"mc",q:"Which best describes the function of past continuous in this sentence: 'The wind was howling and the rain was lashing the windows.'?",options:["Describing a completed action","Interrupting another action","Setting the scene","Expressing a habit"],a:2,exp:"Past continuous is used to set the scene and create atmosphere in narrative writing."},
      {id:"ptc051",type:"error",q:"She was work on her assignment when the internet went down.",a:"She was working on her assignment when the internet went down.",exp:"Past continuous requires verb-ing: 'was working', not 'was work'."},
      {id:"ptc052",type:"error",q:"The students was discussing the project when the professor entered.",a:"The students were discussing the project when the professor entered.",exp:"Plural 'students' requires 'were', not 'was': 'were discussing'."},
      {id:"ptc053",type:"error",q:"While he was reading, she was cooked dinner.",a:"While he was reading, she was cooking dinner.",exp:"Both parallel actions need past continuous: 'was cooking', not 'was cooked'."},
      {id:"ptc054",type:"error",q:"At 8 p.m. last night, I was watched a documentary about environmental policy.",a:"At 8 p.m. last night, I was watching a documentary about environmental policy.",exp:"Past continuous requires verb-ing: 'was watching', not 'was watched'."},
      {id:"ptc055",type:"error",q:"The government were implementing new policies when the crisis began.",a:"The government was implementing new policies when the crisis began.",exp:"Singular 'government' requires 'was': 'was implementing'."},
      {id:"ptc056",type:"error",q:"She was knowing the importance of education when she decided to become a teacher.",a:"She knew the importance of education when she decided to become a teacher.",exp:"'Know' is stative and cannot be used in continuous. Use simple past: 'knew'."},
      {id:"ptc057",type:"error",q:"While the researchers collecting data, they discovered an unexpected pattern.",a:"While the researchers were collecting data, they discovered an unexpected pattern.",exp:"Missing auxiliary 'were'. Past continuous requires subject + were + verb-ing."},
      {id:"ptc058",type:"error",q:"The patient was not feel well when the nurse checked on her.",a:"The patient was not feeling well when the nurse checked on her.",exp:"Past continuous: was + not + verb-ing. 'Feeling' is the correct form."},
      {id:"ptc059",type:"error",q:"Did the team was preparing for the presentation when you arrived?",a:"Was the team preparing for the presentation when you arrived?",exp:"Past continuous question: Was + subject + verb-ing? Do not use 'Did' with continuous forms."},
      {id:"ptc060",type:"error",q:"He were studying at the library while his friends was playing football.",a:"He was studying at the library while his friends were playing football.",exp:"Singular 'he' = 'was'; plural 'friends' = 'were'. Both require correct subject-verb agreement."},
      {id:"ptc061",type:"error",q:"The economy was slow recovering from the global financial crisis.",a:"The economy was slowly recovering from the global financial crisis.",exp:"Adverb form: 'slowly' (not 'slow') modifies 'recovering'."},
      {id:"ptc062",type:"error",q:"At that moment, the committee was consider several different proposals.",a:"At that moment, the committee was considering several different proposals.",exp:"Past continuous requires verb-ing: 'was considering', not 'was consider'."},
      {id:"ptc063",type:"error",q:"The children were played in the schoolyard when it started to rain.",a:"The children were playing in the schoolyard when it started to rain.",exp:"Past continuous requires verb-ing: 'were playing', not 'were played'."},
      {id:"ptc064",type:"error",q:"She was writeing her thesis when she received the scholarship offer.",a:"She was writing her thesis when she received the scholarship offer.",exp:"Spelling: drop the silent -e before -ing: write → writing, not 'writeing'."},
      {id:"ptc065",type:"error",q:"While the doctor explained the diagnosis, the patient was listening carefully.",a:"While the doctor was explaining the diagnosis, the patient was listening carefully.",exp:"Both parallel actions should be in past continuous: 'was explaining' and 'was listening'."},
      {id:"ptc066",type:"error",q:"The team were not make any progress on the research during that period.",a:"The team was not making any progress on the research during that period.",exp:"Singular 'team' (formal) = 'was'. Continuous requires verb-ing: 'making'."},
      {id:"ptc067",type:"error",q:"As the minister was speak, the audience was becoming increasingly restless.",a:"As the minister was speaking, the audience was becoming increasingly restless.",exp:"Past continuous requires verb-ing: 'was speaking', not 'was speak'."},
      {id:"ptc068",type:"error",q:"The researchers was analysing the blood samples when they noticed the contamination.",a:"The researchers were analysing the blood samples when they noticed the contamination.",exp:"Plural 'researchers' requires 'were': 'were analysing'. Australian spelling: analysing."},
      {id:"ptc069",type:"error",q:"He was belonging to three professional organisations at that time.",a:"He belonged to three professional organisations at that time.",exp:"'Belong' is stative and cannot be used in continuous. Use simple past: 'belonged'."},
      {id:"ptc070",type:"error",q:"The university was not offered enough support to struggling students at that time.",a:"The university was not offering enough support to struggling students at that time.",exp:"Past continuous requires verb-ing: 'was not offering', not 'was not offered' (which is passive)."},
      {id:"ptc071",type:"transform",q:"She studied for the exam. [Rewrite as an action in progress at 8 p.m. last night]",a:"She was studying for the exam at 8 p.m. last night.",exp:"Change simple past to past continuous to show the action in progress at a specific moment."},
      {id:"ptc072",type:"transform",q:"The researchers were analysing the data. The power went out. [Combine with 'when']",a:"The researchers were analysing the data when the power went out.",exp:"Past continuous (background) + 'when' + simple past (interruption)."},
      {id:"ptc073",type:"transform",q:"She was writing her report. [Make negative]",a:"She was not writing her report.",exp:"Negative past continuous: was + not + verb-ing."},
      {id:"ptc074",type:"transform",q:"Was the government negotiating a trade deal? [Change to a statement]",a:"The government was negotiating a trade deal.",exp:"Remove inversion: subject + was + verb-ing."},
      {id:"ptc075",type:"transform",q:"The professor lectured. The students took notes. [Rewrite as parallel past continuous actions with 'while']",a:"The professor was lecturing while the students were taking notes.",exp:"Both actions in past continuous connected by 'while': was lecturing, were taking."},
      {id:"ptc076",type:"transform",q:"It rained heavily. The wind blew hard. Visibility was poor. [Rewrite to set the scene using past continuous]",a:"It was raining heavily, the wind was blowing hard, and visibility was poor.",exp:"Past continuous for scene-setting. 'Was poor' stays as a state (adjective complement)."},
      {id:"ptc077",type:"transform",q:"She was not paying attention during the safety briefing. [Make into a question]",a:"Was she paying attention during the safety briefing?",exp:"Question (affirmative): Was + subject + verb-ing? Remove 'not' for a positive question."},
      {id:"ptc078",type:"transform",q:"The economy was recovering. Then a second crisis struck. [Combine with 'when']",a:"The economy was recovering when a second crisis struck.",exp:"Past continuous (ongoing situation) + 'when' + simple past (sudden event)."},
      {id:"ptc079",type:"transform",q:"Students are preparing for the final exam right now. [Rewrite in past continuous with 'at that time']",a:"Students were preparing for the final exam at that time.",exp:"Change present continuous to past continuous: are → were. Change 'right now' to 'at that time'."},
      {id:"ptc080",type:"transform",q:"She was conducting an experiment while he was recording the results. [Make the first clause negative]",a:"She was not conducting an experiment while he was recording the results.",exp:"Negative: was + not + verb-ing. Only the first clause changes."},
      {id:"ptc081",type:"transform",q:"The committee discussed the proposal all afternoon. [Rewrite in past continuous to emphasise duration]",a:"The committee was discussing the proposal all afternoon.",exp:"Past continuous emphasises the duration of the ongoing action: was discussing."},
      {id:"ptc082",type:"transform",q:"What did she do when the alarm rang? She was reading in the library. [Combine into one sentence]",a:"She was reading in the library when the alarm rang.",exp:"Past continuous (background action) + when + simple past (interruption)."},
      {id:"ptc083",type:"transform",q:"The hospital was treating patients during the emergency. [Make into a question with 'How many patients']",a:"How many patients was the hospital treating during the emergency?",exp:"Question: How many + noun + was + subject + verb-ing?"},
      {id:"ptc084",type:"transform",q:"He was walking to the university. He met his supervisor. [Combine with 'as']",a:"As he was walking to the university, he met his supervisor.",exp:"'As' + past continuous (background) + comma + simple past (event)."},
      {id:"ptc085",type:"transform",q:"The government was not addressing the housing crisis effectively. [Rewrite as a negative question to express surprise]",a:"Wasn't the government addressing the housing crisis effectively?",exp:"Negative question expresses surprise/disbelief: Wasn't + subject + verb-ing?"}
    ]
  }
];
